<script lang="ts">
  import { movementPct } from '../lib/decision';
  import { deltaClass, factor, gameTime, instrumentState, readingPublished, signed, weather, weatherTrusted } from '../lib/format';
  import { miniParkPath, type StaticGeometry } from '../lib/geometry';
  import type { Game } from '../lib/types';
  import InstrumentState from './InstrumentState.svelte';

  export let games: Game[];
  export let raw: StaticGeometry | null = null;
  export let focusGamePk: number | null = null;
  export let compareGamePks: number[] = [];
  export let onselect: (gamePk: number) => void = () => {};
  export let onpin: (gamePk: number) => void = () => {};
</script>

<!-- svelte-ignore a11y_no_noninteractive_tabindex -- scroll region must be keyboard-focusable so keyboard users can scroll the dense ledger -->
<div class="ledger-wrap" role="region" tabindex="0" aria-label="Dense game ledger">
  <table class="ledger">
    <thead>
      <tr><th>GAME</th><th>TIME</th><th>VENUE</th><th class="num">FACTOR Δ</th><th class="num">RUN PF</th><th class="num">HR PF</th><th class="num">CARRY</th><th class="num">CROSS</th><th class="num">TEMP</th><th class="num">AIR</th><th>STATE</th><th>ACTION</th></tr>
    </thead>
    <tbody>
      {#each games as game (game.game_pk)}
        {@const glyphPath = miniParkPath(raw, game.home_team)}
        {@const movement = movementPct(game)}
        {@const state = instrumentState(game)}
        {@const published = readingPublished(game)}
        {@const trusted = weatherTrusted(game)}
        <tr class:is-selected={focusGamePk === game.game_pk} class:is-pinned={compareGamePks.includes(game.game_pk)}>
          <td data-label="Game"><a href={`#/game/${game.game_pk}`} aria-label={`${game.away_team} at ${game.home_team}, first pitch ${gameTime(game.game_time)}, open full station`}><strong>{game.away_team}</strong> at <strong>{game.home_team}</strong></a></td>
          <td data-label="Time">{gameTime(game.game_time)}</td>
          <td data-label="Venue"><span class="ledger-venue">{#if glyphPath}<svg class="park-glyph park-glyph--row" viewBox="0 0 40 40" aria-hidden="true"><path d={glyphPath} /></svg>{/if}<span>{game.venue}</span></span></td>
          <td data-label="Factor movement" class="num">
            {#if published && movement != null}
              <span class="delta-mini" aria-hidden="true"><i class={deltaClass(movement)} style={`--m:${Math.min(100, Math.abs(movement) / 30 * 100)}%`}></i></span>
            {/if}
            {!published || movement == null ? '—' : `${movement > 0 ? '+' : ''}${movement}%`}
          </td>
          <td data-label="Run PF" class="num">{factor(published ? game.daily_pf_runs : null)}</td>
          <td data-label="HR PF" class="num">{factor(published ? game.daily_pf_hr : null)}</td>
          <td data-label="Carry" class="num wind-derived">{signed(trusted ? game.wind_carry_mph : null, 1)}</td>
          <td data-label="Cross" class="num wind-derived">{signed(trusted ? game.wind_cross_mph ?? null : null, 1)}</td>
          <td data-label="Temp" class="num">{trusted ? weather(game.temperature_f, '°') : '—'}</td>
          <td data-label="Air" class="num">{trusted && game.air_density_index != null && Number.isFinite(game.air_density_index) ? game.air_density_index.toFixed(1) : '—'}</td>
          <td data-label="State"><InstrumentState {state} /></td>
          <td data-label="Action" class="ledger-actions">{#if published}<button type="button" onclick={() => onselect(game.game_pk)}>Inspect</button><button class:active={compareGamePks.includes(game.game_pk)} type="button" onclick={() => onpin(game.game_pk)}>{compareGamePks.includes(game.game_pk) ? 'Pinned' : 'Pin'}</button>{:else}<a href={`#/game/${game.game_pk}`}>Open</a>{/if}</td>
        </tr>
      {/each}
    </tbody>
  </table>
</div>
