<script lang="ts">
  import { onMount } from 'svelte';
  import { edgeFade } from '../lib/edgeFade';
  import { movementLabel } from '../lib/decision';
  import { factor } from '../lib/format';
  import type { Game } from '../lib/types';
  export let example: Game | undefined;

  const sections = [
    ['field-states', 'Instrument states'],
    ['worked-example', 'Worked example'],
    ['approaches', 'Model path'],
    ['sources', 'Sources'],
    ['glossary', 'Glossary'],
    ['doctrine', 'Honesty doctrine'],
  ] as const;

  let current = sections[0][0];

  onMount(() => {
    const observer = new IntersectionObserver((entries) => {
      const active = entries
        .filter((entry) => entry.isIntersecting)
        .sort((a, b) => Math.abs(a.boundingClientRect.top) - Math.abs(b.boundingClientRect.top))[0];
      if (active) current = active.target.id as typeof current;
    }, { rootMargin: '-40% 0px -55% 0px' });

    for (const [id] of sections) {
      const section = document.getElementById(id);
      if (section) observer.observe(section);
    }
    return () => observer.disconnect();
  });
</script>

