<script lang="ts">
  import { onMount, tick } from 'svelte';
  import ComparisonTray from '../components/ComparisonTray.svelte';
  import GameCard from '../components/GameCard.svelte';
  import Ledger from '../components/Ledger.svelte';
  import WindFieldStrip from '../components/WindFieldStrip.svelte';
  import { movementPct } from '../lib/decision';
  import { edgeFade } from '../lib/edgeFade';
  import { dateLabel, gameTime, instrumentState, readingPublished, signed, sortGames, weatherTrusted } from '../lib/format';
  import { loadStaticGeometry, miniParkPath, type StaticGeometry } from '../lib/geometry';
  import type { LoadedMarket } from '../lib/market';
  import { parseSlateState, slateStateHash, type SlateFilter, type SlateSort } from '../lib/slateState';
  import type { DashboardPayload, Game, LoadedSlate } from '../lib/types';

  const hourMinute = new Intl.DateTimeFormat(undefined, { hour: 'numeric', minute: '2-digit' });

  function firstPitchRange(games: Game[]): string {
    const timed = games
      .map((game) => ({ game, time: new Date(game.game_time).getTime() }))
      .filter(({ time }) => Number.isFinite(time))
      .sort((a, b) => a.time - b.time);
    if (!timed.length) return 'not available';
    return `${hourMinute.format(new Date(timed[0].time))}–${gameTime(timed[timed.length - 1].game.game_time)}`;
  }

  function temperatureRange(games: Game[]): string {
    const temperatures = games
      .map((game) => game.temperature_f)
      .filter((value): value is number => typeof value === 'number' && Number.isFinite(value));
    if (!temperatures.length) return 'not available';
    return `${Math.round(Math.min(...temperatures))}–${Math.round(Math.max(...temperatures))}°F`;
  }

  function strongestOpenAirCarry(games: Game[]): Game | null {
    let strongest: Game | null = null;
    let magnitude = -1;
    for (const game of games) {
      const carry = game.wind_carry_mph;
      if (Boolean(game.dome_active) || typeof carry !== 'number' || !Number.isFinite(carry)) continue;
      if (Math.abs(carry) > magnitude) {
        strongest = game;
        magnitude = Math.abs(carry);
      }
    }
    return strongest;
  }

  export let payload: DashboardPayload;
  export let source: LoadedSlate['source'];
  export let stale = false;
  export let market: LoadedMarket | null = null;
  let sort: SlateSort = 'edge';
  let filter: SlateFilter = 'all';
  let ledger = false;
  let focusGamePk: number | null = null;
  let compareGamePks: number[] = [];
  let raw: StaticGeometry | null = null;

  function writeSlateUrl() {
    if (typeof history === 'undefined') return;
    const hash = slateStateHash({ focusGamePk, compareGamePks, filter, sort, ledger });
    history.replaceState(history.state, '', `${location.pathname}${location.search}${hash}`);
  }

  function selectGame(gamePk: number) {
    focusGamePk = gamePk;
    writeSlateUrl();
    void tick().then(() => document.querySelector('.comparison-tray')?.scrollIntoView({ block: 'nearest' }));
  }

  function togglePin(gamePk: number) {
    focusGamePk = gamePk;
    if (compareGamePks.includes(gamePk)) compareGamePks = compareGamePks.filter((value) => value !== gamePk);
    else if (compareGamePks.length < 4) compareGamePks = [...compareGamePks, gamePk];
    writeSlateUrl();
    void tick().then(() => document.querySelector('.comparison-tray')?.scrollIntoView({ block: 'start' }));
  }

  function removePin(gamePk: number) {
    compareGamePks = compareGamePks.filter((value) => value !== gamePk);
    writeSlateUrl();
  }

  function clearPins() {
    compareGamePks = [];
    writeSlateUrl();
  }

  function setFilter(next: SlateFilter) {
    filter = next;
    writeSlateUrl();
  }

  function toggleLedger() {
    ledger = !ledger;
    writeSlateUrl();
  }

  onMount(() => {
    let active = true;
    void loadStaticGeometry().then((value) => {
      if (active) raw = value;
    });
    const view = parseSlateState(location.hash);
    const validGamePks = new Set(payload.games.filter(readingPublished).map((game) => game.game_pk));
    sort = view.sort;
    filter = view.filter;
    ledger = view.ledger;
    focusGamePk = view.focusGamePk != null && validGamePks.has(view.focusGamePk) ? view.focusGamePk : null;
    compareGamePks = view.compareGamePks.filter((gamePk) => validGamePks.has(gamePk));
    return () => { active = false; };
  });

  $: filtered = payload.games.filter((game) => {
    if (filter === 'roof') return Boolean(game.dome_active);
    if (filter === 'open') return !Boolean(game.dome_active);
    if (filter === 'incomplete') return !weatherTrusted(game);
    return true;
  });
  $: games = sortGames(filtered, sort);
  $: publishedGames = payload.games.filter(readingPublished);
  $: trustedGames = payload.games.filter(weatherTrusted);
  $: positive = publishedGames.filter((game) => (movementPct(game) ?? 0) >= 3).length;
  $: negative = publishedGames.filter((game) => (movementPct(game) ?? 0) <= -3).length;
  $: pitchRange = firstPitchRange(payload.games);
  $: temperatures = temperatureRange(trustedGames);
  $: strongestCarry = strongestOpenAirCarry(trustedGames);
  $: carrySummary = strongestCarry && typeof strongestCarry.wind_carry_mph === 'number'
    ? `${signed(strongestCarry.wind_carry_mph, 1)} mph · ${strongestCarry.away_team}·${strongestCarry.home_team}`
    : 'not available';
  $: domeCount = payload.games.filter((game) => Boolean(game.dome_active)).length;
  $: states = payload.games.map(instrumentState);
  $: verified = states.filter((state) => ['OBSERVED', 'VERIFIED FORECAST'].includes(state.label)).length;
  $: projected = states.filter((state) => state.label === 'PROJECTED').length;
  $: incomplete = states.filter((state) => ['INCOMPLETE', 'SOURCE UNVERIFIED', 'DATA CONFLICT'].includes(state.label)).length;
</script>

<section class="slate-intro">
  <div>
    <p class="eyebrow">Station report · {dateLabel(payload.date)} · {payload.games.length} games</p>
    <h1>The Slate</h1>
    <p class="lede">Today’s air against each park’s own baseline. The movement—not the reputation—is the signal.</p>
  </div>
  <div class="slate-station">
    <dl class="slate-counts" aria-label="Slate summary">
      <div><dt>games</dt><dd>{payload.games.length}</dd></div>
      <div><dt>lift</dt><dd>{positive}</dd></div>
      <div><dt>drag</dt><dd>{negative}</dd></div>
    </dl>
    <details class="slate-synopsis-drawer">
      <summary><span>Slate conditions</span><strong>{pitchRange} · {temperatures}</strong></summary>
      <dl class="slate-synopsis" aria-label="Slate conditions summary">
        <div><dt>First pitch</dt><dd>{pitchRange}</dd></div>
        <div><dt>Temp range</dt><dd>{temperatures}</dd></div>
        <div><dt>Strongest carry</dt><dd class:wind-value={strongestCarry !== null}>{carrySummary}</dd></div>
        <div><dt>Roofs</dt><dd>{domeCount} closed</dd></div>
        <div><dt>Instrument</dt><dd>{verified} verified · {projected} lineup-projected · {incomplete} held</dd></div>
      </dl>
    </details>
  </div>
</section>

<section class="slate-controls" aria-label="Slate controls">
  <div class="control-group" use:edgeFade>
    <span class="control-label">Filter</span>
    <div class="pill-row" role="group" aria-label="Filter games">
      {#each [['all', 'All'], ['open', 'Open air'], ['roof', 'Roof'], ['incomplete', 'Incomplete']] as option}
        <button class:active={filter === option[0]} aria-pressed={filter === option[0]} type="button" onclick={() => setFilter(option[0] as SlateFilter)}>{option[1]}</button>
      {/each}
    </div>
  </div>
  <label class="sort-control"><span class="control-label">Sort</span>
    <select bind:value={sort} onchange={writeSlateUrl}>
      <option value="edge">Largest movement</option>
      <option value="time">First pitch</option>
      <option value="wind">Carry wind</option>
      <option value="venue">Venue</option>
    </select>
  </label>
  <button class="view-toggle" class:active={ledger} type="button" onclick={toggleLedger} aria-pressed={ledger}>
    <span aria-hidden="true">{ledger ? '▦' : '☷'}</span>{ledger ? 'Card mode' : 'Ledger mode'}
  </button>
</section>

{#if games.length === 0}
  <div class="slate-empty"><strong>No games match this filter.</strong><button type="button" onclick={() => setFilter('all')}>Show the full slate</button></div>
{:else if ledger}
  <Ledger {games} {raw} {focusGamePk} {compareGamePks} onselect={selectGame} onpin={togglePin} />
{:else}
  <div class="game-grid">
    {#each games as game, index (game.game_pk)}
      {@const glyphPath = miniParkPath(raw, game.home_team)}
      <GameCard
        {game}
        {glyphPath}
        {market}
        slateDate={payload.date}
        lead={sort === 'edge' && index === 0 && readingPublished(game) && movementPct(game) != null}
        selected={focusGamePk === game.game_pk}
        pinned={compareGamePks.includes(game.game_pk)}
        movementRank={sort === 'edge' && index < 3 && readingPublished(game) && movementPct(game) != null ? index + 1 : null}
        onpin={togglePin}
      />
    {/each}
  </div>
{/if}

{#if trustedGames.length || focusGamePk !== null || compareGamePks.length}<section class="field-desk" aria-label="Whole-slate analysis desk">
  {#if trustedGames.length}<WindFieldStrip games={trustedGames} {focusGamePk} {compareGamePks} onselect={selectGame} />{/if}
  {#if focusGamePk !== null || compareGamePks.length}
    <ComparisonTray games={payload.games} {focusGamePk} {compareGamePks} {payload} {source} {stale} {market} onpin={togglePin} onselect={selectGame} onremove={removePin} onclear={clearPins} />
  {/if}
</section>{/if}
