// FE-4 — share-card render engine. Draws a 1200×630 (OG-sized) card to a canvas so the
// same pixels display in-app and download as a PNG (no SVG/img font isolation). Colors come
// from the LIVE design tokens (theme-aware; tokens.css stays the single source, no new hex),
// and the honesty/legal framing is drawn into every card. No accuracy/performance claims ever;
// no auto-upload; no access code. The deploy-time per-game OG generation is a later Engine
// contract — this is the client render.

import type { DashboardPayload, Game } from './types';
import { dateLabel, factor, gameTime, instrumentState, readingPublished, signed, sortGames, weatherTrusted } from './format';
import { staticVenueForTeam, type StaticGeometry } from './geometry';
import { movementPct } from './decision';

const W = 1200;
const H = 630;
const SCALE = 2; // retina backing store

const DISPLAY = 'DM Serif Display';
const BODY = 'IBM Plex Sans';
const MONO = 'JetBrains Mono';

type Tokens = Record<string, string>;

function readTokens(): Tokens {
  const cs = getComputedStyle(document.documentElement);
  const get = (name: string) => cs.getPropertyValue(name).trim() || '#000';
  return {
    paper: get('--paper'),
    paperRaised: get('--paper-raised'),
    ink: get('--ink'),
    inkSoft: get('--ink-soft'),
    inkFaint: get('--ink-faint'),
    rule: get('--rule'),
    ruleStrong: get('--rule-strong'),
    accent: get('--accent'),
    wind: get('--wind'),
    favorable: get('--favorable'),
    adverse: get('--adverse'),
    amber: get('--amber'),
    suspended: get('--suspended'),
  };
}

/** Ensure the exact faces/weights the card draws are loaded before we rasterize. */
export async function prepareFonts(): Promise<void> {
  const faces = [`400 80px "${DISPLAY}"`, `500 28px "${MONO}"`, `400 22px "${BODY}"`];
  try {
    await Promise.all(faces.map((f) => document.fonts.load(f)));
    await document.fonts.ready;
  } catch {
    /* fall back to system fonts if the API is unavailable */
  }
}

// Provenance travels ONTO the exported artifact — the in-app data-ribbon does not.
// A fixture/stale card must carry its own "not live" marking so a downstream viewer
// of the PNG is never misled (honesty doctrine on a public, permanent surface).
export interface CardMeta {
  source: 'network' | 'cache' | 'fixture';
  stale: boolean;
  modelVersion: string;
}

interface Provenance {
  sourceLabel: string;
  modelVersion: string;
  marker: { text: string; color: string } | null;
}

function provenanceOf(tokens: Tokens, meta: CardMeta): Provenance {
  const modelVersion = (meta.modelVersion || 'unknown').toUpperCase();
  if (meta.source === 'fixture') {
    return { sourceLabel: 'OFFLINE FIXTURE', modelVersion, marker: { text: 'SAMPLE — NOT LIVE DATA', color: tokens.adverse } };
  }
  if (meta.stale) {
    return { sourceLabel: 'STALE COPY', modelVersion, marker: { text: 'STALE · VERIFY BEFORE USE', color: tokens.adverse } };
  }
  if (meta.source === 'cache') {
    return { sourceLabel: 'DEVICE COPY', modelVersion, marker: null };
  }
  return { sourceLabel: 'LIVE PAYLOAD', modelVersion, marker: null };
}

function stateColor(tokens: Tokens, level: string): string {
  if (level === 'high') return tokens.favorable;
  if (level === 'medium') return tokens.amber;
  if (level === 'suspended') return tokens.suspended;
  return tokens.adverse;
}

function deltaColor(tokens: Tokens, value: number | null): string {
  if (value == null) return tokens.inkFaint;
  if (value > 0.004) return tokens.favorable;
  if (value < -0.004) return tokens.adverse;
  return tokens.inkSoft;
}

function chrome(ctx: CanvasRenderingContext2D, tokens: Tokens, dateStr: string, prov: Provenance): void {
  ctx.fillStyle = tokens.paper;
  ctx.fillRect(0, 0, W, H);
  // faint instrument grid
  ctx.strokeStyle = tokens.rule;
  ctx.lineWidth = 1;
  ctx.globalAlpha = 0.6;
  for (let x = 80; x < W; x += 160) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, H); ctx.stroke(); }
  for (let y = 78; y < H; y += 80) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(W, y); ctx.stroke(); }
  ctx.globalAlpha = 1;
  // frame
  ctx.strokeStyle = tokens.ruleStrong;
  ctx.lineWidth = 2;
  ctx.strokeRect(40, 40, W - 80, H - 80);
  // wordmark
  ctx.strokeStyle = tokens.ink;
  ctx.lineWidth = 3;
  ctx.beginPath(); ctx.arc(105, 100, 26, 0, Math.PI * 2); ctx.stroke();
  ctx.lineWidth = 2;
  ctx.beginPath(); ctx.moveTo(84, 86); ctx.lineTo(126, 114); ctx.moveTo(84, 114); ctx.lineTo(126, 86); ctx.stroke();
  ctx.textAlign = 'left';
  ctx.fillStyle = tokens.ink;
  ctx.font = `500 22px "${MONO}"`;
  ctx.fillText('P R E S T I G E', 150, 96);
  ctx.fillStyle = tokens.accent;
  ctx.font = `500 13px "${MONO}"`;
  ctx.fillText('A T M O S P H E R I C', 150, 118);
  // date + provenance line, right
  ctx.textAlign = 'right';
  ctx.fillStyle = tokens.inkFaint;
  ctx.font = `500 16px "${MONO}"`;
  ctx.fillText(dateStr.toUpperCase(), W - 86, 98);
  ctx.fillStyle = prov.marker ? prov.marker.color : tokens.inkFaint;
  ctx.font = `500 12px "${MONO}"`;
  ctx.fillText(`${prov.sourceLabel} · ${prov.modelVersion}`, W - 86, 120);
  ctx.textAlign = 'left';
  // non-live stamp — the artifact must declare when it is fixture or stale
  if (prov.marker) {
    ctx.font = `500 15px "${MONO}"`;
    const tw = ctx.measureText(prov.marker.text).width;
    ctx.strokeStyle = prov.marker.color;
    ctx.lineWidth = 1.5;
    ctx.strokeRect(86, 146, tw + 42, 32);
    ctx.fillStyle = prov.marker.color;
    ctx.beginPath(); ctx.arc(105, 162, 4, 0, Math.PI * 2); ctx.fill();
    ctx.fillText(prov.marker.text, 118, 167);
  }
}

function footer(ctx: CanvasRenderingContext2D, tokens: Tokens): void {
  ctx.textAlign = 'left';
  ctx.fillStyle = tokens.inkSoft;
  ctx.font = `400 20px "${BODY}"`;
  ctx.fillText('Weather physics, with its uncertainty left on.', 86, 556);
  ctx.fillStyle = tokens.inkFaint;
  ctx.font = `500 13px "${MONO}"`;
  ctx.fillText('ANALYTICS — NOT WAGERING ADVICE · 21+', 86, 582);
  ctx.textAlign = 'right';
  ctx.fillStyle = tokens.accent;
  ctx.font = `500 14px "${MONO}"`;
  ctx.fillText('PRESTIGE ATMOSPHERIC', W - 86, 582);
  ctx.textAlign = 'left';
}

function stateChip(ctx: CanvasRenderingContext2D, tokens: Tokens, x: number, y: number, label: string, color: string): void {
  ctx.font = `500 15px "${MONO}"`;
  const w = ctx.measureText(label).width + 28;
  ctx.strokeStyle = color;
  ctx.lineWidth = 1.5;
  ctx.strokeRect(x, y - 20, w, 30);
  ctx.fillStyle = color;
  ctx.beginPath(); ctx.arc(x + 14, y - 5, 3.5, 0, Math.PI * 2); ctx.fill();
  ctx.fillText(label, x + 24, y);
}

function setup(canvas: HTMLCanvasElement): CanvasRenderingContext2D {
  canvas.width = W * SCALE;
  canvas.height = H * SCALE;
  const ctx = canvas.getContext('2d');
  if (!ctx) throw new Error('2d context unavailable');
  ctx.scale(SCALE, SCALE);
  ctx.textBaseline = 'alphabetic';
  return ctx;
}

function drawParkGeometry(
  ctx: CanvasRenderingContext2D,
  tokens: Tokens,
  raw: StaticGeometry | null,
  team: string,
): void {
  if (!raw) return;
  const venue = staticVenueForTeam(raw, team);
  if (!venue) return;

  const homeX = 620;
  const homeY = 470;
  const scale = 0.38;
  ctx.save();
  ctx.beginPath();
  ctx.moveTo(homeX, homeY);
  for (let index = 0; index < raw.angles_deg.length; index += 1) {
    const theta = (raw.angles_deg[index] * Math.PI) / 180;
    const distance = venue.wall_distance_ft[index];
    ctx.lineTo(homeX + distance * Math.sin(theta) * scale, homeY - distance * Math.cos(theta) * scale);
  }
  ctx.closePath();
  ctx.strokeStyle = tokens.ruleStrong;
  ctx.lineWidth = 2;
  ctx.lineJoin = 'miter';
  ctx.stroke();
  ctx.textAlign = 'center';
  ctx.fillStyle = tokens.inkFaint;
  ctx.font = `500 12px "${MONO}"`;
  ctx.fillText(`GEOMETRY · ${String(raw.geometry_version).slice(0, 8)}`, homeX, 498);
  ctx.restore();
}

/** Draw one game's edge as a share card. */
export function renderGameCard(
  canvas: HTMLCanvasElement,
  game: Game,
  date: string,
  meta: CardMeta,
  raw: StaticGeometry | null = null,
): void {
  const tokens = readTokens();
  const ctx = setup(canvas);
  chrome(ctx, tokens, dateLabel(date), provenanceOf(tokens, meta));

  // venue + matchup
  ctx.fillStyle = tokens.ink;
  ctx.font = `400 74px "${DISPLAY}"`;
  ctx.fillText(game.venue, 84, 236);
  ctx.fillStyle = tokens.inkSoft;
  ctx.font = `500 26px "${MONO}"`;
  ctx.fillText(`${game.away_team}  at  ${game.home_team}   ·   ${gameTime(game.game_time)}`, 86, 280);

  const state = instrumentState(game);
  const hasPublishedReading = readingPublished(game);
  const hasTrustedWeather = weatherTrusted(game);
  stateChip(ctx, tokens, 86, 330, state.label, stateColor(tokens, state.level));

  // Canonical movement hero: a factor ratio versus this park's baseline, never a runs count.
  const movement = hasPublishedReading ? movementPct(game) : null;
  ctx.fillStyle = tokens.accent;
  ctx.font = `500 18px "${MONO}"`;
  ctx.fillText('FACTOR MOVEMENT', 86, 404);
  ctx.fillStyle = tokens.inkFaint;
  ctx.font = `400 15px "${BODY}"`;
  ctx.fillText('game-time vs this park’s baseline', 86, 426);
  ctx.fillStyle = deltaColor(tokens, movement);
  ctx.font = `500 104px "${MONO}"`;
  ctx.fillText(movement == null ? '—' : `${movement > 0 ? '+' : ''}${movement}%`, 82, 516);

  drawParkGeometry(ctx, tokens, raw, game.home_team);

  // stat stack, right
  const stats: Array<[string, string]> = [
    ['SCORING FACTOR', factor(hasPublishedReading ? game.daily_pf_runs : null)],
    ['HOME RUN FACTOR', factor(hasPublishedReading ? game.daily_pf_hr : null)],
    ['CARRY WIND', hasTrustedWeather && game.wind_carry_mph != null ? `${signed(game.wind_carry_mph, 1)} mph` : '—'],
  ];
  let sy = 358;
  for (const [label, value] of stats) {
    ctx.fillStyle = tokens.inkFaint;
    ctx.font = `500 15px "${MONO}"`;
    ctx.fillText(label, 792, sy);
    ctx.fillStyle = label === 'CARRY WIND' ? tokens.wind : tokens.ink;
    ctx.font = `500 34px "${MONO}"`;
    ctx.fillText(value, 792, sy + 38);
    sy += 64;
  }

  footer(ctx, tokens);
}

/** Draw the whole slate as a shareable digest. */
export function renderDigestCard(canvas: HTMLCanvasElement, payload: DashboardPayload, date: string, meta: CardMeta): void {
  const tokens = readTokens();
  const ctx = setup(canvas);
  chrome(ctx, tokens, dateLabel(date), provenanceOf(tokens, meta));

  const games = payload.games;
  const published = games.filter(readingPublished);
  const sourceAlerts = games.filter((game) => instrumentState(game).label === 'SOURCE UNVERIFIED').length;

  ctx.fillStyle = tokens.ink;
  ctx.font = `400 74px "${DISPLAY}"`;
  ctx.fillText('The Slate', 84, 236);
  ctx.fillStyle = tokens.inkSoft;
  ctx.font = `400 22px "${BODY}"`;
  ctx.fillText('Today’s air against each park’s own baseline — the movement, not the reputation.', 86, 276);

  // summary tiles
  const tiles: Array<[string, string]> = [[String(games.length), 'GAMES'], [String(published.length), 'PUBLISHED'], [String(sourceAlerts), 'SOURCE ALERTS']];
  let tx = 86;
  for (const [n, label] of tiles) {
    ctx.fillStyle = tokens.ink;
    ctx.font = `500 40px "${MONO}"`;
    ctx.fillText(n, tx, 344);
    ctx.fillStyle = tokens.inkFaint;
    ctx.font = `500 13px "${MONO}"`;
    ctx.fillText(label, tx, 366);
    tx += 120;
  }

  // top movers
  ctx.fillStyle = tokens.accent;
  ctx.font = `500 16px "${MONO}"`;
  ctx.fillText(sourceAlerts ? 'PUBLISHED MOVEMENT · SOURCE PROVISIONAL' : 'VERIFIED MOVEMENT', 86, 418);
  const movers = sortGames(published, 'edge').slice(0, 3);
  let my = 452;
  for (const g of movers) {
    ctx.fillStyle = tokens.ink;
    ctx.font = `500 24px "${MONO}"`;
    ctx.fillText(`${g.away_team} at ${g.home_team}`, 86, my);
    ctx.fillStyle = tokens.inkFaint;
    ctx.font = `400 18px "${BODY}"`;
    ctx.fillText(g.venue, 320, my);
    const movement = movementPct(g);
    ctx.fillStyle = deltaColor(tokens, movement);
    ctx.textAlign = 'right';
    ctx.font = `500 26px "${MONO}"`;
    ctx.fillText(movement == null ? '—' : `${movement > 0 ? '+' : ''}${movement}%`, W - 86, my);
    ctx.textAlign = 'left';
    my += 36;
  }
  if (!movers.length) {
    ctx.fillStyle = tokens.adverse;
    ctx.font = `500 20px "${MONO}"`;
    ctx.fillText('NO VERIFIED WEATHER READINGS IN THIS COPY', 86, 464);
    ctx.fillStyle = tokens.inkSoft;
    ctx.font = `400 17px "${BODY}"`;
    ctx.fillText('Schedule and lineup evidence remain available in the app.', 86, 494);
  }

  footer(ctx, tokens);
}

/** Download the rendered canvas as a PNG. No upload; the user saves it locally. */
export function downloadCard(canvas: HTMLCanvasElement, filename: string): void {
  canvas.toBlob((blob) => {
    if (!blob) return;
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    a.remove();
    // Defer the revoke: WebKit/Firefox read the blob on a later tick, and revoking
    // synchronously can abort the save.
    setTimeout(() => URL.revokeObjectURL(url), 0);
  }, 'image/png');
}

/** Copy a permalink. Returns true on success. */
export async function copyLink(url: string): Promise<boolean> {
  try {
    await navigator.clipboard.writeText(url);
    return true;
  } catch {
    return false;
  }
}
