export type Route =
  | { name: 'slate' }
  | { name: 'game'; gamePk: number }
  | { name: 'share'; gamePk: number }
  | { name: 'digest' }
  | { name: 'batters' }
  | { name: 'trust' }
  | { name: 'method' }
  | { name: 'not-found'; path: string };

export function normalizeHash(hash: string): string {
  const raw = hash.replace(/^#/, '') || '/';
  const [path] = raw.split('?');
  const normalized = `/${path}`.replace(/\/+/g, '/').replace(/\/$/, '');
  return normalized || '/';
}

export function parseRoute(hash: string): Route {
  const path = normalizeHash(hash);
  if (path === '/') return { name: 'slate' };
  if (path === '/batters') return { name: 'batters' };
  if (path === '/trust') return { name: 'trust' };
  if (path === '/method') return { name: 'method' };
  if (path === '/digest') return { name: 'digest' };
  const share = path.match(/^\/game\/(\d+)\/share$/);
  if (share) return { name: 'share', gamePk: Number(share[1]) };
  const game = path.match(/^\/game\/(\d+)$/);
  if (game) return { name: 'game', gamePk: Number(game[1]) };
  return { name: 'not-found', path };
}

export function routeTitle(route: Route): string {
  switch (route.name) {
    case 'slate': return 'The Slate';
    case 'game': return 'Game Detail';
    case 'share': return 'Share Card';
    case 'digest': return 'Daily Digest';
    case 'batters': return 'Lineup Board';
    case 'trust': return 'Data Health';
    case 'method': return 'Methodology';
    default: return 'Not Found';
  }
}
