import { meaning } from './meaning';
import type { Game, InstrumentState, NullableNumber } from './types';

export function factor(value: NullableNumber): string {
  return value == null || !Number.isFinite(value) ? '—' : value.toFixed(3);
}

export function signed(value: NullableNumber, digits = 3): string {
  if (value == null || !Number.isFinite(value)) return '—';
  if (Math.abs(value) < 0.5 * 10 ** -digits) return (0).toFixed(digits);
  return `${value > 0 ? '+' : ''}${value.toFixed(digits)}`;
}

export function weather(value: NullableNumber, suffix: string, digits = 0): string {
  return value == null || !Number.isFinite(value) ? 'not available' : `${value.toFixed(digits)}${suffix}`;
}

export function gameTime(iso: string): string {
  const date = new Date(iso);
  if (Number.isNaN(date.getTime())) return 'Time not available';
  return new Intl.DateTimeFormat(undefined, {
    hour: 'numeric',
    minute: '2-digit',
    timeZoneName: 'short',
  }).format(date);
}

export function dateLabel(value: string): string {
  const date = new Date(`${value}T12:00:00Z`);
  if (Number.isNaN(date.getTime())) return value;
  return new Intl.DateTimeFormat(undefined, {
    weekday: 'long',
    month: 'long',
    day: 'numeric',
    timeZone: 'UTC',
  }).format(date);
}

export function ageHours(generatedAt: string, now = Date.now()): number {
  const generated = new Date(generatedAt).getTime();
  return Number.isFinite(generated) ? Math.max(0, (now - generated) / 3_600_000) : Number.POSITIVE_INFINITY;
}

export type WeatherReceiptBasis = 'forecast' | 'observation' | 'indoor' | 'unknown';

const UNVERIFIED_WEATHER_SOURCES = new Set(['neutral_fallback', 'forecast_cache_stale', 'unknown', 'unverified']);

function hasValidTimestamp(value: string | null | undefined): value is string {
  return typeof value === 'string' && value.trim().length > 0 && Number.isFinite(Date.parse(value));
}

function hasVerifiableSource(game: Game): boolean {
  const source = game.weather_source?.trim().toLowerCase();
  if (!source) return false;
  return !UNVERIFIED_WEATHER_SOURCES.has(source);
}

/** The semantic basis of the receipt. `weather_observed_at` is never used to validate a declared forecast. */
export function weatherReceiptBasis(game: Game): WeatherReceiptBasis {
  if (Boolean(game.dome_active) || game.weather_basis?.trim().toLowerCase() === 'indoor') return 'indoor';
  const declared = game.weather_basis?.trim().toLowerCase();
  if (declared === 'observation') return hasValidTimestamp(game.weather_observed_at) ? 'observation' : 'unknown';
  if (declared === 'forecast') {
    return hasValidTimestamp(game.weather_valid_at) && hasValidTimestamp(game.weather_fetched_at) ? 'forecast' : 'unknown';
  }
  if (declared) return 'unknown';
  if (hasValidTimestamp(game.weather_observed_at)) return 'observation';
  if (hasValidTimestamp(game.weather_valid_at) && hasValidTimestamp(game.weather_fetched_at)) return 'forecast';
  return 'unknown';
}

/** True only for a named, non-degraded source with the timestamps required by its declared basis. */
export function weatherReceiptVerified(game: Game): boolean {
  if (Boolean(game.dome_active)) return true;
  const basis = weatherReceiptBasis(game);
  return hasVerifiableSource(game)
    && game.weather_degraded === false
    && (basis === 'forecast' || basis === 'observation');
}

export function weatherSourceLabel(game: Game): string {
  const source = game.weather_source?.trim();
  if (!source) return 'Not verified';
  const known: Record<string, string> = {
    open_meteo_batch: 'Open-Meteo',
    open_meteo_venue_fallback: 'Open-Meteo',
    open_meteo_forecast: 'Open-Meteo',
    open_meteo_observation_cache: 'Open-Meteo observation',
    met_norway_locationforecast: 'MET Norway',
    forecast_cache: 'Verified forecast cache',
    forecast_cache_stale: 'Stale forecast cache',
    indoor_default: 'Roof-controlled environment',
    neutral_fallback: 'No live weather source',
    fixture: 'Interface fixture',
  };
  const normalized = source.toLowerCase();
  if (known[normalized]) return known[normalized];
  return source.replace(/[_-]+/g, ' ').replace(/\b\w/g, (letter) => letter.toUpperCase());
}

export function weatherBasisLabel(game: Game): string {
  const basis = weatherReceiptBasis(game);
  if (basis === 'forecast') return 'Sourced forecast';
  if (basis === 'observation') return 'Weather observation';
  if (basis === 'indoor') return 'Roof-controlled environment';
  return 'Receipt incomplete';
}

function evidenceTime(value: string | null | undefined): string | null {
  if (!hasValidTimestamp(value)) return null;
  return new Intl.DateTimeFormat(undefined, {
    month: 'short',
    day: 'numeric',
    hour: 'numeric',
    minute: '2-digit',
    timeZoneName: 'short',
  }).format(new Date(value));
}

export function weatherReceiptDetail(game: Game): string {
  const basis = weatherReceiptBasis(game);
  if (basis === 'forecast') {
    return `valid ${evidenceTime(game.weather_valid_at)} · fetched ${evidenceTime(game.weather_fetched_at)}`;
  }
  if (basis === 'observation') return `observed ${evidenceTime(game.weather_observed_at)}`;
  if (basis === 'indoor') return 'outdoor wind physics suspended';
  return 'source or time receipt incomplete';
}

export function instrumentState(game: Game): InstrumentState {
  if (game.data_conflict) {
    return { level: 'low', label: 'DATA CONFLICT', reason: game.data_conflict_reason ?? 'Duplicate feed rows disagree; this reading is withheld.' };
  }
  if (Boolean(game.dome_active)) {
    return { level: 'suspended', label: 'ROOF', reason: 'Outdoor wind physics are suspended.' };
  }
  if (game.daily_pf_runs == null || game.wind_carry_mph == null) {
    return { level: 'low', label: 'INCOMPLETE', reason: 'Weather input is missing; no daily factor is asserted.' };
  }
  if (!weatherReceiptVerified(game)) {
    const detail = game.weather_degraded_reason?.trim();
    return {
      level: 'low',
      label: 'SOURCE UNVERIFIED',
      reason: detail || 'Model output is present, but the weather source or time receipt is not fully verified.',
    };
  }
  const lineupsConfirmed = game.has_lineups
    && game.home_lineup_status === 'CONFIRMED'
    && game.away_lineup_status === 'CONFIRMED';
  if (!lineupsConfirmed) {
    return { level: 'medium', label: 'PROJECTED', reason: 'Weather is verified; at least one lineup is not confirmed.' };
  }
  if (weatherReceiptBasis(game) === 'forecast') {
    return { level: 'high', label: 'VERIFIED FORECAST', reason: 'A sourced forecast with a valid-time receipt is present and both lineups are confirmed.' };
  }
  return { level: 'high', label: 'OBSERVED', reason: 'A sourced weather observation is present and both lineups are confirmed.' };
}

/** A model factor exists and is internally renderable, even if its source receipt is provisional. */
export function readingPublished(game: Game): boolean {
  const state = instrumentState(game);
  return !['INCOMPLETE', 'DATA CONFLICT'].includes(state.label)
    && typeof game.seasonal_pf_runs === 'number' && Number.isFinite(game.seasonal_pf_runs)
    && typeof game.daily_pf_runs === 'number' && Number.isFinite(game.daily_pf_runs);
}

/** Weather-derived measurements may be asserted only when their source receipt is complete. */
export function weatherTrusted(game: Game): boolean {
  if (game.data_conflict) return false;
  if (Boolean(game.dome_active)) return true;
  return game.daily_pf_runs != null && game.wind_carry_mph != null && weatherReceiptVerified(game);
}

export type MeaningSide = 'positive' | 'negative' | 'neutral';

/** Plain-language reading of a park factor: 1.12 → "favors hitters (+12%)". */
export function factorMeaning(value: NullableNumber): { text: string; side: MeaningSide } | null {
  if (value == null || !Number.isFinite(value)) return null;
  const pct = Math.round((value - 1) * 100);
  if (pct > 0) return { text: `favors hitters (+${pct}%)`, side: 'positive' };
  if (pct < 0) return { text: `favors pitchers (−${Math.abs(pct)}%)`, side: 'negative' };
  return { text: 'neutral park effect', side: 'neutral' };
}

/** Plain-language reading of the wind-carry component. */
export function windMeaning(carry: NullableNumber): { text: string; side: MeaningSide } | null {
  if (carry == null || !Number.isFinite(carry)) return null;
  if (carry > 1) return { text: 'carrying the ball out', side: 'positive' };
  if (carry < -1) return { text: 'holding the ball in', side: 'negative' };
  return { text: 'calm air', side: 'neutral' };
}

export function deltaClass(value: NullableNumber): 'positive' | 'negative' | 'neutral' | 'missing' {
  if (value == null) return 'missing';
  if (value > 0.004) return 'positive';
  if (value < -0.004) return 'negative';
  return 'neutral';
}

export function sortGames(games: Game[], key: 'edge' | 'time' | 'wind' | 'venue'): Game[] {
  return [...games].sort((a, b) => {
    if (key === 'time') return new Date(a.game_time).getTime() - new Date(b.game_time).getTime();
    if (key === 'venue') return a.venue.localeCompare(b.venue);
    // 'edge' = Largest movement, ranked by the SAME model adjustment the card shows (single source of
    // truth), never the mislabeled pf_weather_delta_runs.
    const edge = (g: Game) => meaning(g.seasonal_pf_runs, g.daily_pf_runs).adjustmentPct;
    const av = readingPublished(a) ? key === 'wind' && weatherTrusted(a) ? a.wind_carry_mph : key === 'edge' ? edge(a) : null : null;
    const bv = readingPublished(b) ? key === 'wind' && weatherTrusted(b) ? b.wind_carry_mph : key === 'edge' ? edge(b) : null : null;
    if (av == null && bv == null) return 0;
    if (av == null) return 1;
    if (bv == null) return -1;
    return Math.abs(bv) - Math.abs(av);
  });
}
