<script lang="ts">
  import InstrumentState from '../components/InstrumentState.svelte';
  import { now } from '../lib/clock';
  import { evidenceLabel, freshnessLabel, movementLabel } from '../lib/decision';
  import { gameTime, instrumentState, readingPublished, signed, weatherTrusted } from '../lib/format';
  import type { DashboardPayload, Game, LoadedSlate } from '../lib/types';

  export let slate: DashboardPayload;
  export let source: LoadedSlate['source'];
  export let stale = false;

  type Readiness = 'ready' | 'watch' | 'hold';
  type LineupFilter = 'all' | Readiness;

  let filter: LineupFilter = 'all';

  function normalizedStatus(value: unknown): string {
    return typeof value === 'string' && value.trim() ? value.trim().toUpperCase() : 'UNKNOWN';
  }

  function bothConfirmed(game: Game): boolean {
    return game.has_lineups
      && normalizedStatus(game.away_lineup_status) === 'CONFIRMED'
      && normalizedStatus(game.home_lineup_status) === 'CONFIRMED';
  }

  function readinessFor(game: Game): Readiness {
    if (bothConfirmed(game)) return 'ready';
    if (game.has_lineups) return 'watch';
    return 'hold';
  }

  function lineupLabel(game: Game, value: unknown): string {
    if (!game.has_lineups) return 'Pending publication';
    const status = normalizedStatus(value);
    if (status === 'CONFIRMED') return 'Confirmed';
    if (status === 'PROJECTED') return 'Projected';
    if (status === 'UNKNOWN') return 'Not confirmed';
    return status.toLowerCase().replace(/\b\w/g, (letter) => letter.toUpperCase());
  }

  function readinessLabel(value: Readiness): string {
    if (value === 'ready') return 'CONFIRMED';
    if (value === 'watch') return 'LINEUP WATCH';
    return 'PENDING';
  }

  $: rows = slate.games
    .map((game) => ({ game, state: instrumentState(game), readiness: readinessFor(game) }))
    .sort((a, b) => {
      const order: Record<Readiness, number> = { ready: 0, watch: 1, hold: 2 };
      return order[a.readiness] - order[b.readiness]
        || Date.parse(a.game.game_time) - Date.parse(b.game.game_time);
    });
  $: readyCount = rows.filter((row) => row.readiness === 'ready').length;
  $: watchCount = rows.filter((row) => row.readiness === 'watch').length;
  $: pendingCount = rows.filter((row) => row.readiness === 'hold').length;
  $: visibleRows = filter === 'all' ? rows : rows.filter((row) => row.readiness === filter);
</script>

<header class="page-header lineup-page-header">
  <div>
    <p class="eyebrow">Today's confirmation desk</p>
    <h1>Lineup Board</h1>
    <p class="lede">See which matchups have confirmed lineups, which still use projections, and which batting orders have not published yet.</p>
  </div>
  <span class="model-stamp" class:receipt-alert={stale}>{evidenceLabel(source)} · {freshnessLabel(slate.generated_at, $now)}{stale ? ' · verify age' : ''}</span>
</header>

<section class="lineup-summary" aria-labelledby="lineup-summary-title">
  <div><p class="eyebrow">Subscriber read</p><h2 id="lineup-summary-title">Slate readiness</h2></div>
  <dl>
    <div><dt>Confirmed</dt><dd>{readyCount}</dd><small>both batting orders published</small></div>
    <div><dt>Lineup watch</dt><dd>{watchCount}</dd><small>one or both orders still projected</small></div>
    <div><dt>Pending</dt><dd>{pendingCount}</dd><small>batting orders not published</small></div>
  </dl>
</section>

<nav class="lineup-filters" aria-label="Filter lineup readiness">
  <button type="button" class:active={filter === 'all'} aria-pressed={filter === 'all'} onclick={() => filter = 'all'}>All <span>{rows.length}</span></button>
  <button type="button" class:active={filter === 'ready'} aria-pressed={filter === 'ready'} onclick={() => filter = 'ready'}>Confirmed <span>{readyCount}</span></button>
  <button type="button" class:active={filter === 'watch'} aria-pressed={filter === 'watch'} onclick={() => filter = 'watch'}>Lineup watch <span>{watchCount}</span></button>
  <button type="button" class:active={filter === 'hold'} aria-pressed={filter === 'hold'} onclick={() => filter = 'hold'}>Pending <span>{pendingCount}</span></button>
</nav>

{#if visibleRows.length}
  <section class="lineup-board" aria-label="Today's lineup readiness">
    {#each visibleRows as row, index (row.game.game_pk)}
      <article class="lineup-card readiness-{row.readiness}">
        <header>
          <span class="lineup-card__index">{String(index + 1).padStart(2, '0')}</span>
          <div><p>{row.game.venue}</p><small>{gameTime(row.game.game_time)}</small></div>
          <strong>{readinessLabel(row.readiness)}</strong>
        </header>
        <h3>{row.game.away_team} <i>at</i> {row.game.home_team}</h3>
        <div class="lineup-sides">
          <div><span>{row.game.away_team} away</span><strong>{lineupLabel(row.game, row.game.away_lineup_status)}</strong><small>{row.game.away_pitcher ?? 'Starter not posted'}</small></div>
          <div><span>{row.game.home_team} home</span><strong>{lineupLabel(row.game, row.game.home_lineup_status)}</strong><small>{row.game.home_pitcher ?? 'Starter not posted'}</small></div>
        </div>
        <dl class="lineup-readings">
          <div><dt>Model movement</dt><dd>{readingPublished(row.game) ? `${movementLabel(row.game)}${weatherTrusted(row.game) ? '' : ' · provisional'}` : 'Withheld for data conflict'}</dd></div>
          <div><dt>Carry wind</dt><dd>{Boolean(row.game.dome_active) ? 'Roof controlled' : weatherTrusted(row.game) && row.game.wind_carry_mph != null ? `${signed(row.game.wind_carry_mph, 1)} mph` : 'Source unverified'}</dd></div>
        </dl>
        <footer><InstrumentState state={row.state} /><a href={`#/game/${row.game.game_pk}`}>Open full station <span aria-hidden="true">→</span></a></footer>
      </article>
    {/each}
  </section>
{:else}
  <section class="slate-empty"><p class="eyebrow">No rows in this view</p><h2>Choose another readiness filter.</h2><button type="button" onclick={() => filter = 'all'}>Show every game</button></section>
{/if}
