// FE-2 — vendored static park geometry (frontend-owned asset, lazy-loaded).
//
// The Engine's BE-1 handoff (`data/handoff/park_geometry.static.json`, geometry_version
// 0d644ad6…) is vendored byte-for-byte into `public/`. It is polar: for each of 91 angles
// (-45° LF foul line → 0° CF → +45° RF foul line) a wall distance (ft) and wall height (ft),
// per team. This module fetches it once and converts a park to the cartesian `ParkGeometry`
// the Park Wind Diagram renders (home plate at the bottom, CF straight up).

import type { ParkGeometry, Point } from './types';

export interface RawVenue {
  venue_id: string;
  cf_azimuth: number;
  dome_type: number;
  wall_distance_ft: number[];
  wall_height_ft: number[];
}

export interface StaticGeometry {
  schema_version: number | string;
  geometry_version: string;
  angles_deg: number[];
  venues: Record<string, RawVenue>;
}

// SVG placement — matches ParkWindDiagram's `viewBox="0 0 640 390"`: home plate at the
// bottom centre, center field straight up. One scale for both axes so parks keep their
// true proportions; 0.64 px/ft fits the deepest fields (~420 ft) inside the field envelope.
const HOME_X = 320;
const HOME_Y = 344;
const PX_PER_FT = 0.64;

let cache: StaticGeometry | null = null;
let inflight: Promise<StaticGeometry | null> | null = null;

const TEAM_ALIASES: Record<string, string> = {
  CHW: 'CWS',
};

function isStaticGeometry(value: unknown): value is StaticGeometry {
  return typeof value === 'object' && value !== null
    && Array.isArray((value as StaticGeometry).angles_deg)
    && typeof (value as StaticGeometry).venues === 'object' && (value as StaticGeometry).venues !== null;
}

/** Fetch the vendored geometry once (frontend origin, never the data base). Null if absent. */
export async function loadStaticGeometry(): Promise<StaticGeometry | null> {
  if (cache) return cache;
  if (inflight) return inflight;
  inflight = (async () => {
    try {
      const res = await fetch('./park_geometry.static.json', { cache: 'force-cache' });
      if (!res.ok) return null;
      const data: unknown = await res.json();
      if (!isStaticGeometry(data)) return null;
      cache = data;
      return cache;
    } catch {
      return null;
    }
  })();
  return inflight;
}

/** Normalize payload abbreviations to the keys used by the vendored geometry file. */
export function normalizeGeometryTeam(team: string): string {
  const normalized = team.trim().toUpperCase();
  return TEAM_ALIASES[normalized] ?? normalized;
}

/** Return a complete, finite wall record or null; incomplete geometry is never invented. */
export function staticVenueForTeam(raw: StaticGeometry | null, team: string): RawVenue | null {
  if (!raw || raw.angles_deg.length < 2 || !raw.angles_deg.every(Number.isFinite)) return null;
  const venue = raw.venues[normalizeGeometryTeam(team)];
  if (!venue
    || !Array.isArray(venue.wall_distance_ft)
    || venue.wall_distance_ft.length !== raw.angles_deg.length
    || !venue.wall_distance_ft.every((distance) => Number.isFinite(distance) && distance > 0)) {
    return null;
  }
  return venue;
}

/**
 * Convert one team's polar wall to the diagram's cartesian `ParkGeometry`. The wall
 * polygon is [home plate, …91 wall points…]; closing it back to home draws the foul
 * lines plus the outfield wall. Returns null if the team is absent (→ diagram stays in
 * its honest "GEOMETRY NOT PRESENT" gate; no generic shape is ever substituted).
 */
export function parkGeometryForTeam(raw: StaticGeometry | null, team: string): ParkGeometry | null {
  if (!raw) return null;
  const venue = staticVenueForTeam(raw, team);
  if (!venue) return null;
  const wall: Point[] = [{ x: HOME_X, y: HOME_Y }];
  const wall_height_ft: number[] = [0];
  for (let i = 0; i < raw.angles_deg.length; i += 1) {
    const theta = (raw.angles_deg[i] * Math.PI) / 180;
    const distance = venue.wall_distance_ft[i];
    wall.push({
      x: HOME_X + distance * Math.sin(theta) * PX_PER_FT,
      y: HOME_Y - distance * Math.cos(theta) * PX_PER_FT,
    });
    const wallHeight = venue.wall_height_ft?.[i];
    wall_height_ft.push(typeof wallHeight === 'number' && Number.isFinite(wallHeight) ? wallHeight : 0);
  }
  return {
    source: `park_geometry.static · ${raw.geometry_version.slice(0, 8)}`,
    orientation_deg: venue.cf_azimuth,
    wall,
    wall_height_ft,
    wall_distance_ft: venue.wall_distance_ft,
  };
}

/**
 * Build a compact park-outline path for repeated UI glyphs. The full geometry remains
 * available to the detail and share renderers; this path samples to at most 60 points
 * and rounds to one decimal place to keep repeated markup small and stable.
 */
export function miniParkPath(raw: StaticGeometry | null, team: string, size = 40): string | null {
  if (!raw || !Number.isFinite(size) || size <= 0) return null;
  const venue = staticVenueForTeam(raw, team);
  if (!venue) return null;

  const maxDistance = Math.max(...venue.wall_distance_ft);
  if (!Number.isFinite(maxDistance) || maxDistance <= 0) return null;

  const maxWallPoints = 59;
  const step = Math.max(1, Math.ceil((raw.angles_deg.length - 1) / (maxWallPoints - 1)));
  const indices: number[] = [];
  for (let index = 0; index < raw.angles_deg.length; index += step) indices.push(index);
  const finalIndex = raw.angles_deg.length - 1;
  if (indices.at(-1) !== finalIndex) indices.push(finalIndex);

  const round = (value: number) => Math.round(value * 10) / 10;
  const homeX = round(size / 2);
  const homeY = round(size * 0.95);
  const scale = (size * 0.55) / maxDistance;
  const wallPoints = indices.map((index) => {
    const theta = (raw.angles_deg[index] * Math.PI) / 180;
    const distance = venue.wall_distance_ft[index];
    const x = round(homeX + distance * Math.sin(theta) * scale);
    const y = round(homeY - distance * Math.cos(theta) * scale);
    return `${x},${y}`;
  });

  return `M ${homeX},${homeY} L ${wallPoints.join(' L ')} Z`;
}
