<script lang="ts">
  import type { Point, TrajectoryPair } from '../lib/types';
  import { drawFlight } from '../lib/motion';
  export let trajectories: TrajectoryPair[] | undefined;
  export let fixture = false;

  let revealed: boolean[] = [];

  const toSvg = (point: Point): Point => ({ x: 42 + point.x * 4.6, y: 245 - point.y * 2.6 });

  const path = (points: Point[]) => {
    if (!points.length) return '';
    return `M ${points.map(toSvg).map((point) => `${point.x},${point.y}`).join(' L ')}`;
  };

  // Both arcs are drawn at ONE speed, so the tonight ball is still in the air after the
  // neutral one has landed. The extra drawing time IS the extra carry — no eased curve
  // stands in for ballistics.
  const flight = (points: Point[]) => {
    const { length, seconds } = drawFlight(points.map(toSvg));
    return `--len:${length}; --dur:${seconds}s`;
  };

  const landing = (points: Point[]): Point | null => points.length ? toSvg(points[points.length - 1]) : null;
  const apex = (points: Point[]): Point | null => {
    if (!points.length) return null;
    return points.map(toSvg).reduce((highest, point) => point.y < highest.y ? point : highest);
  };
  const reveal = (index: number) => {
    revealed[index] = true;
    revealed = revealed;
  };

  $: pairs = (trajectories ?? [])
    .filter((pair) => pair.neutral.length > 0 && pair.tonight.length > 0)
    .slice(0, 3);
  $: trajectories, revealed = [];
</script>

{#if pairs.length}
  <section class="trajectory-theater" aria-labelledby="trajectory-title">
    <header class="section-kicker-row">
      <div><p class="eyebrow">One draw speed · the longer arc is the extra carry</p><h2 id="trajectory-title">Trajectory Theater</h2></div>
      <span class="model-stamp">{pairs[0].model_version}</span>
    </header>
    {#if fixture}<p class="fixture-disclosure">Interface fixture only — these arcs are not a live forecast.</p>{/if}
    <div class="trajectory-stage">
      <svg viewBox="0 0 600 300" role="img" aria-label="Neutral and tonight trajectory comparison">
        <line x1="34" y1="245" x2="566" y2="245" class="ground-line" />
        <path d="M 500 245 V 158" class="wall-line" />
        <text x="506" y="175" class="wall-label">WALL</text>
        {#each pairs as pair, index}
          {@const lastNeutral = landing(pair.neutral)}
          {@const lastTonight = landing(pair.tonight)}
          {@const tonightApex = index === 0 ? apex(pair.tonight) : null}
          <path d={path(pair.neutral)} class="trajectory-neutral" style={flight(pair.neutral)} />
          <path d={path(pair.tonight)} class="trajectory-tonight" style={flight(pair.tonight)} onanimationend={() => reveal(index)} />
          {#if lastNeutral && lastTonight}
            {@const rowY = 258 + index * 13}
            {@const left = Math.min(lastNeutral.x, lastTonight.x)}
            {@const right = Math.max(lastNeutral.x, lastTonight.x)}
            {@const flipLabel = right > 540}
            <g class="flight-annotation" class:revealed={revealed[index]}>
              <line x1={lastNeutral.x} x2={lastNeutral.x} y1="241" y2="249" class="landing-neutral" />
              <line x1={lastTonight.x} x2={lastTonight.x} y1="241" y2="249" class="landing-tonight" />
              <line x1={left} x2={right} y1={rowY} y2={rowY} class="carry-gap" />
              <line x1={left} x2={left} y1={rowY - 2} y2={rowY + 2} class="carry-gap" />
              <line x1={right} x2={right} y1={rowY - 2} y2={rowY + 2} class="carry-gap" />
              <text
                class="carry-gap-label"
                x={flipLabel ? left - 8 : right + 8}
                y={rowY + 3}
                text-anchor={flipLabel ? 'end' : 'start'}
              >{pair.carry_delta_ft > 0 ? '+' : ''}{pair.carry_delta_ft} ft</text>
              {#if tonightApex}
                <text
                  class="trajectory-apex"
                  x={Math.max(60, Math.min(540, tonightApex.x))}
                  y={Math.max(16, tonightApex.y - 8)}
                  text-anchor="middle"
                >{pair.label}</text>
              {/if}
            </g>
          {/if}
        {/each}
      </svg>
      <div class="trajectory-legend"><span class="neutral">neutral air</span><span class="tonight">tonight’s air</span></div>
    </div>
    <div class="trajectory-notes">
      {#each pairs as pair}
        <article>
          <span class="mono">{pair.label}</span>
          <strong>{pair.carry_delta_ft > 0 ? '+' : ''}{pair.carry_delta_ft} ft</strong>
          <p>{pair.clears_wall ? 'Tonight’s arc clears where neutral air does not.' : 'Wall outcome is unchanged.'}</p>
          <small>{pair.source}</small>
        </article>
      {/each}
    </div>
  </section>
{/if}
