<script lang="ts">
  import { onMount } from 'svelte';
  import { copyLink, downloadCard, prepareFonts, renderDigestCard } from '../lib/shareCard';
  import { track } from '../lib/telemetry';
  import type { DashboardPayload } from '../lib/types';

  export let payload: DashboardPayload;
  export let source: 'network' | 'cache' | 'fixture' = 'network';
  export let stale = false;

  let canvas: HTMLCanvasElement | undefined;
  let copied = false;

  async function draw() {
    if (!canvas) return;
    await prepareFonts();
    renderDigestCard(canvas, payload, payload.date, { source, stale, modelVersion: payload.model_version });
    canvas.setAttribute('data-rendered', 'true');
  }

  onMount(() => {
    const observer = new MutationObserver(() => draw());
    observer.observe(document.documentElement, { attributes: true, attributeFilter: ['data-theme'] });
    return () => observer.disconnect();
  });

  // Redraw when the canvas binds or any provenance input changes.
  $: canvas, payload, source, stale, void draw();

  $: permalink = new URL('#/', location.href).toString();

  async function onCopy() {
    copied = await copyLink(permalink);
    track('share', { game_pk: 0, kind: 'digest-copy' });
    setTimeout(() => (copied = false), 2000);
  }
  function onDownload() {
    if (!canvas) return;
    downloadCard(canvas, `prestige-slate-${payload.date}.png`);
    track('share', { game_pk: 0, kind: 'digest-download' });
  }
</script>

<section class="digest-view">
  <a class="back" href="#/">← The Slate</a>
  <h1>Daily digest</h1>
  <p class="lede">The whole slate as one shareable card — where today’s weather edge is, at a glance. Analytics only.</p>
  <div class="card-frame">
    <canvas bind:this={canvas} class="share-canvas"
      aria-label={`Daily digest card for the slate of ${payload.date}`}
    >Daily digest card for the slate of {payload.date}.</canvas>
  </div>
  {#if source !== 'network' || stale}
    <p class="provenance-note">
      {#if source === 'fixture'}This card is rendered from the <strong>offline fixture — sample data, not live</strong>.{:else if source === 'cache'}This card is rendered from a <strong>last-verified device copy</strong> (as of {payload.date}).{/if}
      {#if stale} <strong>The slate is outside its published freshness window</strong> — verify before use.{/if}
      The same marking is drawn onto the downloaded image.
    </p>
  {/if}
  <div class="share-actions">
    <button type="button" class="primary" onclick={onDownload}>Download PNG</button>
    <button type="button" class:copied={copied} aria-live="polite" onclick={onCopy}>{copied ? 'Link copied ✓' : 'Copy link'}</button>
  </div>
  <p class="fineprint">The image renders on your device and is never uploaded. Not wagering advice; 21+ where books are legal.</p>
</section>

<style>
  .digest-view { max-width: 60rem; margin-inline: auto; }
  .back { display: inline-flex; align-items: center; min-height: 2.75rem; margin-bottom: var(--space-6); font-family: var(--font-mono); font-size: .8rem; color: var(--ink-faint); }
  .back:hover { color: var(--ink); }
  h1 { font-family: var(--font-display); font-size: clamp(2rem, 6vw, 3.2rem); margin: 0 0 var(--space-2); }
  .lede { color: var(--ink-soft); margin: 0 0 var(--space-8); max-width: 40rem; }
  .card-frame { border: 1px solid var(--rule); background: var(--paper-raised); padding: var(--space-4); box-shadow: var(--shadow); }
  .share-canvas { width: 100%; height: auto; display: block; }
  .provenance-note { margin-top: var(--space-4); padding: var(--space-3) var(--space-4); border-left: 3px solid var(--adverse); background: var(--adverse-soft); color: var(--ink-soft); font-size: .85rem; max-width: 44rem; }
  .provenance-note strong { color: var(--adverse); }
  .share-actions { display: flex; flex-wrap: wrap; gap: var(--space-3); margin-top: var(--space-6); }
  .share-actions button { min-width: 8.75rem; padding: .7rem 1.15rem; border: 1px solid var(--rule-strong); background: var(--paper); font-family: var(--font-mono); font-size: .78rem; letter-spacing: .04em; transition: background-color 120ms var(--ease-state), border-color 120ms var(--ease-state), color 120ms var(--ease-state), box-shadow 120ms var(--ease-state), transform 80ms var(--ease-state); }
  .share-actions button.primary { background: var(--ink); color: var(--paper); border-color: var(--ink); }
  .share-actions button:hover { border-color: var(--ink); background: var(--paper-raised); }
  .share-actions button.primary:hover { border-color: var(--ink-soft); background: color-mix(in oklch, var(--ink) 88%, var(--paper)); box-shadow: var(--shadow-2); }
  .share-actions button:active { transform: translateY(1px); box-shadow: var(--shadow-inset); }
  .share-actions button.copied { color: var(--favorable); border-color: var(--favorable); }
  .fineprint { margin-top: var(--space-6); color: var(--ink-faint); font-size: .8rem; max-width: 40rem; }
</style>
