<script lang="ts">
  import InstrumentState from '../components/InstrumentState.svelte';
  import { now } from '../lib/clock';
  import { evidenceLabel, freshnessLabel, lineupEvidenceLabel, movementLabel } from '../lib/decision';
  import {
    gameTime,
    instrumentState,
    readingPublished,
    weatherReceiptBasis,
    weatherReceiptDetail,
    weatherSourceLabel,
    weatherTrusted,
  } from '../lib/format';
  import type { DashboardPayload, LoadedSlate } from '../lib/types';

  export let slate: DashboardPayload;
  export let source: LoadedSlate['source'];
  export let stale = false;

  $: rows = [...slate.games]
    .sort((a, b) => Date.parse(a.game_time) - Date.parse(b.game_time))
    .map((game) => ({ game, state: instrumentState(game) }));
  $: scored = slate.games.filter((game) => game.daily_pf_runs != null && Number.isFinite(game.daily_pf_runs)).length;
  $: observed = rows.filter((row) => weatherTrusted(row.game) && weatherReceiptBasis(row.game) === 'observation').length;
  $: forecast = rows.filter((row) => weatherTrusted(row.game) && weatherReceiptBasis(row.game) === 'forecast').length;
  $: projected = rows.filter((row) => row.state.label === 'PROJECTED').length;
  $: roof = rows.filter((row) => row.state.label === 'ROOF').length;
  $: holds = rows.filter((row) => ['INCOMPLETE', 'SOURCE UNVERIFIED', 'DATA CONFLICT'].includes(row.state.label)).length;
  $: conflicts = rows.filter((row) => row.state.label === 'DATA CONFLICT').length;
  $: status = source === 'fixture' ? 'SAMPLE MODE'
    : stale || source === 'cache' ? 'VERIFY FRESHNESS'
    : holds ? 'PARTIAL COVERAGE'
    : 'SLATE OPERATIONAL';
</script>

<header class="page-header"><p class="eyebrow">Evidence, not theater</p><h1>Data Health</h1><p class="lede">A current operating receipt for every game on the loaded slate. Counts, source gaps, and conflicts stay visible; no trust score is invented.</p></header>

<section class="trust-today" aria-labelledby="health-title">
  <div class="section-kicker-row"><div><p class="eyebrow">Data health today</p><h2 id="health-title">Current Slate Receipt</h2></div><span class="model-stamp" class:receipt-alert={stale}>{status}</span></div>
  <p class="health-brief">{slate.games.length} unique games checked · {forecast} verified forecasts · {observed} observations · {projected} lineup-projected · {holds} on data hold</p>
  <dl class="health-ledger">
    <div><dt>Feed</dt><dd>{evidenceLabel(source)}</dd><small>{slate.date}</small></div>
    <div><dt>Freshness</dt><dd>{freshnessLabel(slate.generated_at, $now)}</dd><small>{stale ? 'outside published use window' : 'inside current use window'}</small></div>
    <div><dt>Factor coverage</dt><dd>{scored} of {slate.games.length}</dd><small>published model outputs</small></div>
    <div><dt>Verified forecasts</dt><dd>{forecast}</dd><small>source + valid time + fetch receipt</small></div>
    <div><dt>Verified observations</dt><dd>{observed}</dd><small>sourced weather + observation time</small></div>
    <div><dt>Lineup projection</dt><dd>{projected}</dd><small>weather usable; orders not final</small></div>
    <div><dt>Data holds</dt><dd>{holds}</dd><small>{conflicts ? `${conflicts} conflicting duplicate ${conflicts === 1 ? 'row' : 'rows'}` : 'source or weather coverage'}</small></div>
    <div><dt>Roof controlled</dt><dd>{roof}</dd><small>outdoor physics suspended</small></div>
    <div><dt>Model version</dt><dd>{slate.model_version}</dd><small>generated {slate.generated_at}</small></div>
  </dl>
  <details class="provenance-record"><summary>Open technical provenance</summary><dl><div><dt>Schema</dt><dd>{slate.schema_version ?? 'not declared'}</dd></div><div><dt>Builder</dt><dd>{slate.builder_id ?? 'not emitted'}</dd></div><div><dt>Build sequence</dt><dd>{slate.build_seq ?? 'not emitted'}</dd></div><div><dt>Stale after</dt><dd>{slate.freshness?.stale_after_minutes ? `${slate.freshness.stale_after_minutes} minutes` : 'app fallback: 45 minutes'}</dd></div></dl></details>
</section>

<section class="today-ledger" aria-labelledby="today-ledger-title">
  <div class="section-kicker-row"><div><p class="eyebrow">Game-by-game evidence</p><h2 id="today-ledger-title">Today's Evidence Ledger</h2></div><a class="text-link" href="#/batters">Open lineup board →</a></div>
  <div class="today-ledger__wrap">
    <table>
      <thead><tr><th scope="col">Game</th><th scope="col">State</th><th scope="col">Model movement</th><th scope="col">Lineups</th><th scope="col">Weather source</th><th scope="col"><span class="sr-only">Open</span></th></tr></thead>
      <tbody>
        {#each rows as row (row.game.game_pk)}
          <tr>
            <th scope="row"><strong>{row.game.away_team} at {row.game.home_team}</strong><small>{row.game.venue} · {gameTime(row.game.game_time)}</small></th>
            <td><InstrumentState state={row.state} /></td>
            <td>{readingPublished(row.game) ? movementLabel(row.game) : 'Withheld'}</td>
            <td>{lineupEvidenceLabel(row.game)}</td>
            <td>{weatherSourceLabel(row.game)}<small>{weatherReceiptDetail(row.game)}</small></td>
            <td><a href={`#/game/${row.game.game_pk}`} aria-label={`Open ${row.game.away_team} at ${row.game.home_team}`}>Open →</a></td>
          </tr>
        {/each}
      </tbody>
    </table>
  </div>
</section>
