<script lang="ts">
  import type { Meaning } from '../lib/meaning';
  import type { MarketDisplay } from '../lib/market';
  import { marketRead } from '../lib/marketRead';

  export let display: MarketDisplay | null;
  export let m: Meaning;
  export let compact = false;

  $: read = marketRead(display?.total ?? null, m, display?.freshness ?? null, display?.ageMinutes ?? null);
  $: suspended = read.alignment === 'suspended';
  $: aging = display?.freshness === 'aging' && !suspended;

  function ageText(minutes: number | null): string {
    if (minutes == null) return 'unknown';
    if (minutes < 60) return `${Math.round(minutes)}m ago`;
    return `${Math.max(1, Math.round(minutes / 60))}h ago`;
  }

  const moveText = (rel: string): string =>
    rel === 'toward' ? "toward the model's read"
    : rel === 'against' ? "opposite the model's read"
    : rel === 'unchanged' ? 'unchanged since open'
    : 'no directional read on the move';

  $: glyphAria = read.glyph
    ? `conditions ${read.glyph.air === '↑' ? 'up' : read.glyph.air === '↓' ? 'down' : 'near baseline'}; market ${read.glyph.market === '↑' ? 'lean over' : read.glyph.market === '↓' ? 'lean under' : 'flat'}`
    : undefined;
</script>

{#if compact}
  {#if display && read.postedTotal != null && !suspended}
    <div class="s-item market-span" class:market-stale={suspended}>
      <dt>
        Market total{#if display.sample} · <span class="market-tag sample">SAMPLE</span>{:else if suspended} · <span class="market-tag stale">STALE</span>{:else if aging} · <span class="market-tag aging">{ageText(display.ageMinutes)}</span>{/if}
      </dt>
      <dd>{read.postedTotal}</dd>
      <small>{read.summary}</small>
    </div>
  {/if}
{:else if display && read.postedTotal != null && !suspended}
  <section class="market-read" aria-labelledby="market-title">
    <div class="section-kicker-row">
      <div><p class="eyebrow">Market</p><h2 id="market-title">The Posted Total</h2></div>
      {#if display}
        {#if display.sample}<span class="market-asof sample">SAMPLE · not live odds</span>
        {:else}<span class="market-asof" class:stale={suspended} class:aging>as of {ageText(display.ageMinutes)}</span>{/if}
      {/if}
    </div>

    {#if read.glyph}<div class="market-glyph" aria-label={glyphAria}>AIR {read.glyph.air} · MARKET {read.glyph.market}</div>{/if}
      {#if read.label}<div class="market-verdict"><span class="v-dot hollow" aria-hidden="true"></span>{read.label}</div>{/if}
      <p class="m-conseq">{read.sentence}</p>

      <div class="m-flow">
        <div class="m-row"><span class="m-l">Posted total</span><span class="m-v">{read.postedTotal}</span><span class="m-c">{display.total.book_count ? `derived consensus of ${display.total.book_count} sources` : 'derived consensus'}</span></div>
        {#if read.overPct != null}
          <div class="m-row"><span class="m-l">Juice, vig removed</span><span class="m-v">over {read.overPct}% · under {read.underPct}%</span><span class="m-c">50/50 is a balanced market</span></div>
        {/if}
        {#if read.move}
          <div class="m-row"><span class="m-l">Since open</span><span class="m-v">{read.move.from} → {read.move.to}</span><span class="m-c">{read.move.relation === 'unchanged' ? 'unchanged since open' : `moved ${read.move.delta > 0 ? '+' : ''}${read.move.delta} · ${moveText(read.move.relation)}`}</span></div>
        {/if}
        {#if read.engineRef}
          <div class="m-row"><span class="m-l">Engine market reference</span><span class="m-v">park-adjusted {read.engineRef.parkAdjusted} vs {read.engineRef.posted}</span><span class="m-c">MARKET REFERENCE · Engine-computed · not validated</span></div>
        {/if}
      </div>

      {#if read.overPct != null}
        <details class="m-calc">
          <summary>How this was read</summary>
          <div class="m-calcbody">Books price both sides of a total with a built-in margin — the vig. Removing that margin from the consensus prices implies over {read.overPct}% / under {read.underPct}% on {read.postedTotal}. A balanced market is 50/50; a lean means the market's own pricing sits a shade off its posted number. <span class="dim">Raw sportsbook prices are licensed and not displayed — only this derived read.</span></div>
        </details>
      {/if}

      <p class="market-legal">Market reference · informational, not wagering advice.</p>
  </section>
{/if}
