import { EXPECTED_SCHEMA_LABEL, dataMode, dataUrl, schemaSupported } from './config';
import { fixtureSlate } from './fixture';
import type { AccuracyPayload, BattersPayload, DashboardPayload, LoadedSlate } from './types';

const CACHE_KEY = 'prestige-atmospheric-slate-v1';

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null;
}

function mapCause(error: unknown): string {
  if (isRecord(error) && error.name === 'AbortError') return 'TIMEOUT 4S';
  if (!(error instanceof Error)) return 'NETWORK ERROR';
  if (/^\d{3} /.test(error.message)) return `HTTP ${error.message.slice(0, 3)}`;
  if (error.message.toLowerCase().includes('schema')) return 'BAD PAYLOAD SHAPE';
  if (error instanceof TypeError) return 'NETWORK UNREACHABLE';
  return 'NETWORK ERROR';
}

export function isDashboardPayload(value: unknown): value is DashboardPayload {
  if (!isDashboardEnvelope(value)) return false;
  return value.games.every((game) => {
    const nullableNumber = (item: unknown) => item === undefined || item === null
      || (typeof item === 'number' && Number.isFinite(item));
    const nullableText = (item: unknown) => item === undefined || item === null || typeof item === 'string';
    const numericFields = [
      'temperature_f', 'humidity_pct', 'wind_speed_mph', 'wind_carry_mph', 'wind_cross_mph',
      'air_density_index', 'seasonal_pf_runs', 'daily_pf_runs', 'daily_pf_hr',
      'pf_weather_delta_runs', 'pf_weather_delta_hr', 'wind_venue_sensitivity',
      'home_lineup_pf_hr', 'away_lineup_pf_hr', 'lineup_pf_hr_diff', 'lineup_pf_hr_residual',
      'win_prob_home', 'edge', 'consensus_ratio',
    ];
    const row = game as unknown as Record<string, unknown>;
    if (!numericFields.every((field) => nullableNumber(row[field]))) return false;
    if (!nullableText(game.home_pitcher) || !nullableText(game.away_pitcher)) return false;
    if (game.dome_active !== undefined && typeof game.dome_active !== 'boolean' && typeof game.dome_active !== 'number') return false;
    if (game.has_lineups !== undefined && typeof game.has_lineups !== 'boolean') return false;
    if (game.weather_degraded !== undefined && typeof game.weather_degraded !== 'boolean') return false;
    if (game.weather_source !== undefined && !nullableText(game.weather_source)) return false;
    if (game.weather_observed_at !== undefined && !nullableText(game.weather_observed_at)) return false;
    if (game.weather_valid_at !== undefined && !nullableText(game.weather_valid_at)) return false;
    if (game.weather_fetched_at !== undefined && !nullableText(game.weather_fetched_at)) return false;
    if (game.weather_basis !== undefined && !nullableText(game.weather_basis)) return false;
    return true;
  });
}

function isDashboardEnvelope(value: unknown): value is DashboardPayload {
  if (!isRecord(value) || typeof value.date !== 'string' || typeof value.generated_at !== 'string') return false;
  if (typeof value.model_version !== 'string' || typeof value.predictions_available !== 'boolean') return false;
  if (!Array.isArray(value.games)) return false;
  return value.games.every((game) => isRecord(game)
    && typeof game.game_pk === 'number'
    && typeof game.home_team === 'string'
    && typeof game.away_team === 'string'
    && typeof game.venue === 'string'
    && typeof game.game_time === 'string');
}

type DedupeRow = {
  game_pk: number;
  model_run_at?: string;
  data_conflict?: boolean;
  data_conflict_reason?: string;
};
type DedupeOutput<T> = T & Pick<DedupeRow, 'data_conflict' | 'data_conflict_reason'>;

function comparableRow<T extends DedupeRow>(row: T): string {
  const { data_conflict: _conflict, data_conflict_reason: _reason, ...value } = row;
  return JSON.stringify(value);
}

/** Collapse exact duplicates and visibly flag disagreeing rows instead of silently picking one. */
export function dedupeGames<T extends DedupeRow>(games: T[]): { games: DedupeOutput<T>[]; dropped: number; conflicts: number } {
  const indexByPk = new Map<number, number>();
  const unique: DedupeOutput<T>[] = [];
  let dropped = 0;
  let conflicts = 0;
  for (const game of games) {
    const existingIndex = indexByPk.get(game.game_pk);
    if (existingIndex === undefined) {
      indexByPk.set(game.game_pk, unique.length);
      unique.push(game);
      continue;
    }

    dropped += 1;
    const existing = unique[existingIndex];
    if (comparableRow(existing) === comparableRow(game)) continue;

    conflicts += 1;
    const existingRun = existing.model_run_at ? Date.parse(existing.model_run_at) : Number.NaN;
    const candidateRun = game.model_run_at ? Date.parse(game.model_run_at) : Number.NaN;
    const winner = Number.isFinite(candidateRun) && (!Number.isFinite(existingRun) || candidateRun > existingRun)
      ? game
      : existing;
    unique[existingIndex] = {
      ...winner,
      data_conflict: true,
      data_conflict_reason: 'Duplicate feed rows disagree; model values are withheld until the publisher resolves them.',
    } as T;
  }
  return { games: unique, dropped, conflicts };
}

async function fetchJson(path: string, timeoutMs = 4_000): Promise<unknown> {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), timeoutMs);
  try {
    const response = await fetch(path, { cache: 'no-store', signal: controller.signal });
    if (!response.ok) throw new Error(`${response.status} ${response.statusText}`);
    const contentType = response.headers.get('content-type')?.toLowerCase() ?? '';
    if (!contentType.includes('json')) throw new Error(`schema artifact returned ${contentType || 'an unknown content type'}`);
    return await response.json();
  } finally {
    clearTimeout(timeout);
  }
}

function cachedSlate(): DashboardPayload | null {
  try {
    const cached = localStorage.getItem(CACHE_KEY);
    const value: unknown = cached ? JSON.parse(cached) : null;
    if (!isDashboardPayload(value)) return null;
    // Read-path firewall, symmetric with the write path: a cache written by a
    // prior build whose schema this build no longer supports must not be served
    // as a trusted device copy.
    if (!schemaSupported(value.schema_version)) return null;
    // Defense in depth: a cache written by a build before the dedupe fix could still hold a duplicate
    // game_pk, which would crash the keyed render the moment it is served as a device copy.
    const { games, dropped } = dedupeGames(value.games);
    return dropped > 0 ? { ...value, games } : value;
  } catch {
    return null;
  }
}

export async function loadSlate(): Promise<LoadedSlate> {
  if (dataMode === 'fixture') {
    return { payload: fixtureSlate, source: 'fixture', note: 'Forced offline fixture (VITE_DATA_BASE=fixture).' };
  }
  try {
    const value = await fetchJson(dataUrl('data.json'));
    if (!isDashboardEnvelope(value)) throw new Error('data.json did not match the dashboard envelope');
    if (!schemaSupported(value.schema_version)) {
      // Recognized shape, unsupported contract version. Never present it as live:
      // degrade to the last verified copy (else the labeled fixture) and name the
      // cause. This is the honesty firewall for a silent contract change at G1+.
      const received = String(value.schema_version ?? 'unknown');
      const schemaMismatch = { received, expected: EXPECTED_SCHEMA_LABEL };
      const fallback = cachedSlate();
      if (fallback) {
        return { payload: fallback, source: 'cache', schemaMismatch,
          note: `Data format changed (schema ${received}); showing the last verified device copy until the app updates.` };
      }
      return { payload: fixtureSlate, source: 'fixture', schemaMismatch,
        note: `Data format changed (schema ${received}); showing a labeled offline fixture until the app updates.` };
    }
    if (!isDashboardPayload(value)) throw new Error('data.json did not match dashboard schema v1');
    const { games: uniqueGames, dropped, conflicts } = dedupeGames(value.games);
    const payload: DashboardPayload = dropped > 0 ? { ...value, games: uniqueGames } : value;
    try { localStorage.setItem(CACHE_KEY, JSON.stringify(payload)); } catch { /* storage may be disabled */ }
    const base = dataMode === 'staging' ? 'Network-first payload · staging source' : 'Network-first payload';
    const exactDuplicates = dropped - conflicts;
    const duplicateNote = [
      conflicts ? `${conflicts} conflicting duplicate ${conflicts === 1 ? 'row' : 'rows'} flagged` : '',
      exactDuplicates ? `${exactDuplicates} exact duplicate ${exactDuplicates === 1 ? 'row' : 'rows'} collapsed` : '',
    ].filter(Boolean).join(' · ');
    return { payload, source: 'network',
      note: duplicateNote ? `${base} · ${duplicateNote}` : base,
      duplicatesCollapsed: dropped,
      duplicateConflicts: conflicts };
  } catch (networkError) {
    const fallback = cachedSlate();
    if (fallback) {
      return { payload: fallback, source: 'cache', note: 'Network unavailable · showing the last verified device copy' };
    }
    return {
      payload: fixtureSlate,
      source: 'fixture',
      note: 'No live payload is reachable · showing a labeled offline fixture',
      detail: networkError instanceof Error ? networkError.message : String(networkError),
      cause: mapCause(networkError),
    };
  }
}

export async function loadOptional<T>(name: string, validate: (value: unknown) => value is T): Promise<T | null> {
  // Fixture mode is hermetic: no network fetch for optional artifacts either, so
  // gated surfaces (batters/accuracy) stay honestly closed and never render real
  // data under an offline-fixture frame. Symmetric with loadSlate's short-circuit.
  if (dataMode === 'fixture') return null;
  try {
    const value = await fetchJson(dataUrl(name));
    return validate(value) ? value : null;
  } catch {
    return null;
  }
}

export function isAccuracyPayload(value: unknown): value is AccuracyPayload {
  return isRecord(value) && typeof value.generated_at === 'string' && isRecord(value.windows)
    && Array.isArray(value.reliability) && Array.isArray(value.venue_bias) && Array.isArray(value.changelog);
}

export function isBattersPayload(value: unknown): value is BattersPayload {
  return isRecord(value) && typeof value.generated_at === 'string' && isRecord(value.validation) && Array.isArray(value.batters);
}
