// Data-source + schema-contract configuration — the G1 switchover kit (FE-3).
//
// The data base is a BUILD-TIME env (Vite inlines `import.meta.env.VITE_*`), so
// flipping fixture → staging → prod is an env change + rebuild — no code edits —
// per DIRECTIVE_FRONTEND FE-3. See docs/STAGING_SOAK.md for the flip procedure.

export type DataMode = 'prod' | 'staging' | 'fixture';

export interface DataSource {
  mode: DataMode;
  /** Base the artifact name is appended to; always ends in `/` or is `./`. */
  base: string;
}

/**
 * Pure resolver (env-independent, so it is directly unit-testable): maps a raw
 * `VITE_DATA_BASE` value to a mode + normalized base URL.
 *   `fixture` forces the labeled offline fixture; `''`/absent resolves artifacts
 *   relative to the deployed page (prod); any other value is a staging base URL
 *   (e.g. `https://…/v2/staging/`), normalized to a trailing slash.
 */
export function resolveDataSource(rawBase: string | undefined | null): DataSource {
  const raw = (rawBase ?? '').trim();
  if (raw === 'fixture') return { mode: 'fixture', base: './' };
  if (raw === '') return { mode: 'prod', base: './' };
  return { mode: 'staging', base: raw.endsWith('/') ? raw : `${raw}/` };
}

const source = resolveDataSource(import.meta.env.VITE_DATA_BASE);

export const dataMode: DataMode = source.mode;

/** Absolute-or-relative URL for a published artifact (data.json, batters.json, accuracy.json). */
export const dataUrl = (name: string): string => `${source.base}${name}`;

/**
 * schema_version values this build renders correctly. The Engine's checked-in
 * contract (`data/_contracts/data.schema.json`) declares schema_version as the
 * NUMBER `1`; the frontend fixture/provisional schema use string forms. We accept
 * both so the G1 flip cannot be broken by that representation gap, and degrade
 * calmly on anything else (see `loadSlate`). Bump this when the frontend is
 * updated for a new contract version.
 */
export const SUPPORTED_SCHEMA_VERSIONS: ReadonlyArray<string | number> = [
  1,
  '1',
  '1.0.0',
  '1.0.0-provisional',
];

/** Human-readable label used in the mismatch banner ("app supports …"). */
export const EXPECTED_SCHEMA_LABEL = 'contract v1';

/**
 * True when a payload's declared schema_version is one this build understands.
 * Absent/empty is tolerated (structural validation still guards the shape); a
 * PRESENT but unrecognized version triggers the calm "data format changed" state.
 */
export function schemaSupported(version: unknown): boolean {
  if (version === undefined || version === null || version === '') return true;
  return SUPPORTED_SCHEMA_VERSIONS.includes(version as string | number);
}
