<script lang="ts">
  import type { Game } from '../lib/types';
  import { gameTime, instrumentState, readingPublished, signed, weather, weatherTrusted, windMeaning } from '../lib/format';
  import { meaning } from '../lib/meaning';
  import { movementLabel } from '../lib/decision';
  import { now } from '../lib/clock';
  import { marketDisplay, type LoadedMarket } from '../lib/market';
  import { track } from '../lib/telemetry';
  import InstrumentState from './InstrumentState.svelte';
  import MarketBlock from './MarketBlock.svelte';
  import MeaningBlock from './MeaningBlock.svelte';

  export let game: Game;
  export let glyphPath: string | null = null;
  export let lead = false;
  export let market: LoadedMarket | null = null;
  export let slateDate: string | null = null;
  export let selected = false;
  export let pinned = false;
  export let movementRank: number | null = null;
  export let onpin: (gamePk: number) => void = () => {};

  $: state = instrumentState(game);
  $: hasPublishedReading = readingPublished(game);
  $: hasTrustedWeather = weatherTrusted(game);
  $: lineupsConfirmed = game.has_lineups
    && game.home_lineup_status === 'CONFIRMED'
    && game.away_lineup_status === 'CONFIRMED';
  $: lineupLabel = lineupsConfirmed ? 'CONFIRMED' : game.has_lineups ? 'PROJECTED' : 'PENDING';
  $: run = meaning(game.seasonal_pf_runs, game.daily_pf_runs);
  $: marketMd = marketDisplay(market, game.game_pk, slateDate, $now);
  $: hrPct = game.daily_pf_hr != null && Number.isFinite(game.daily_pf_hr)
    ? Math.round((game.daily_pf_hr - 1) * 100)
    : null;
  // A domed game has no wind reading — it is suspended, not "calm" (mirrors ROOF everywhere else).
  $: windPhrase = Boolean(game.dome_active) ? { text: 'roof — wind suspended', side: 'neutral' as const } : windMeaning(game.wind_carry_mph);

  function openShare() {
    track('share', { game_pk: game.game_pk, kind: 'open' });
    location.hash = `#/game/${game.game_pk}/share`;
  }
</script>

<article class="game-card state-surface-{state.level}" class:is-lead={lead} class:is-selected={selected} class:is-pinned={pinned} data-game-pk={game.game_pk}>
  <header class="game-card__header">
    <div class="venue-cell">
      {#if glyphPath}<svg class="park-glyph" viewBox="0 0 40 40" aria-hidden="true"><path d={glyphPath} /></svg>{/if}
      <div>
        <p class="venue-name">{game.venue}</p>
        <p class="game-time">{gameTime(game.game_time)}</p>
      </div>
    </div>
    <div class="card-actions">
      {#if Boolean(game.dome_active)}<span class="roof-badge">ROOF ACTIVE</span>{/if}
      <button class="icon-button" type="button" onclick={openShare} aria-label={`Share ${game.away_team} at ${game.home_team}`}>↗</button>
    </div>
  </header>

  {#if movementRank !== null && hasPublishedReading}
    <div class="card-rankline" aria-label={`Rank ${movementRank} movement: ${movementLabel(game)}`}>
      <span>0{movementRank}</span>
      <span>{movementRank === 1 ? 'largest movement' : 'movement watch'}</span>
      <strong>{movementLabel(game)}</strong>
    </div>
  {/if}

  <a class="game-card__link" href={`#/game/${game.game_pk}`} aria-label={`${game.away_team} at ${game.home_team}, first pitch ${gameTime(game.game_time)}, open full station`} onclick={() => track('game_open', { game_pk: game.game_pk })}>
    <div class="matchup">
      <span>{game.away_team}</span><i aria-hidden="true">at</i><span>{game.home_team}</span>
    </div>
    <div class="pitchers"><span>{game.away_pitcher ?? 'Starter not posted'}</span><span>{game.home_pitcher ?? 'Starter not posted'}</span></div>
  </a>

  <div class="game-card__body">
    {#if hasPublishedReading}<MeaningBlock m={run} />

    <dl class="card-support">
      <div class="s-item">
        <dt>Projected home-run environment</dt>
        <dd>{hrPct == null ? 'not available' : `${hrPct > 0 ? '+' : ''}${hrPct}%`}</dd>
        <small>vs MLB average</small>
      </div>
      <div class="s-item wind">
        <dt>{hasTrustedWeather ? 'Wind' : 'Weather source'}</dt>
        <dd>{hasTrustedWeather ? game.wind_carry_mph == null ? '—' : `${signed(game.wind_carry_mph, 1)} mph` : 'unverified'}</dd>
        <small>{hasTrustedWeather ? windPhrase?.text ?? '' : 'vectors hidden · see receipt'}</small>
      </div>
      <MarketBlock compact display={marketMd} m={run} />
    </dl>
    {:else}<div class="card-reading-hold"><p class="eyebrow">Model reading held</p><strong>{state.label}</strong><p>{state.reason}</p></div>{/if}

    <div class="card-evidence">
      <InstrumentState {state} />
      <span class="weather-brief">{hasTrustedWeather ? `${weather(game.temperature_f, '°F')} · ${weather(game.humidity_pct, '%')}` : 'Published factor · source provisional'}</span>
      <span class="lineup-glyph" class:confirmed={lineupsConfirmed} aria-label={`Lineups ${lineupLabel.toLowerCase()}`}>
        <i></i><i></i><i></i> {lineupLabel}
      </span>
      {#if hasPublishedReading}<button class="card-pin" class:active={pinned} type="button" onclick={() => onpin(game.game_pk)} aria-label={`${pinned ? 'Remove' : 'Add'} ${game.away_team} at ${game.home_team} ${pinned ? 'from' : 'to'} comparison`}>
        {pinned ? 'COMPARING ×' : 'COMPARE +'}
      </button>{/if}
    </div>
  </div>
</article>
