import { meaning } from './meaning';
import type { Game, InstrumentState, LoadedSlate } from './types';

export interface LeadSignal {
  label: string;
  detail: string;
}

export function movementPct(game: Game): number | null {
  return meaning(game.seasonal_pf_runs, game.daily_pf_runs).adjustmentPct;
}

export function movementLabel(game: Game): string {
  const value = movementPct(game);
  if (value == null) return 'No game-time adjustment';
  if (value === 0) return 'At park baseline';
  return `${value > 0 ? '+' : ''}${value}% vs park baseline`;
}

export function leadSignal(game: Game): LeadSignal {
  if (Boolean(game.dome_active)) return { label: 'Roof state', detail: 'Outdoor wind suspended' };
  if (typeof game.wind_carry_mph === 'number' && Number.isFinite(game.wind_carry_mph) && Math.abs(game.wind_carry_mph) >= 1) {
    return {
      label: 'Carry wind',
      detail: `${game.wind_carry_mph > 0 ? '+' : ''}${game.wind_carry_mph.toFixed(1)} mph ${game.wind_carry_mph > 0 ? 'out' : 'in'}`,
    };
  }
  if (typeof game.air_density_index === 'number' && Number.isFinite(game.air_density_index)) {
    return { label: 'Air density', detail: `${game.air_density_index.toFixed(1)} index` };
  }
  if (typeof game.temperature_f === 'number' && Number.isFinite(game.temperature_f)) {
    return { label: 'Temperature', detail: `${Math.round(game.temperature_f)}°F` };
  }
  return { label: 'Coverage', detail: 'Inputs incomplete' };
}

export function pitchCountdown(iso: string, now: number): string {
  const pitch = Date.parse(iso);
  if (!Number.isFinite(pitch)) return 'First pitch unavailable';
  const minutes = Math.round((pitch - now) / 60_000);
  if (minutes < -240) return 'Game window passed';
  if (minutes < 0) return 'Game underway';
  if (minutes < 60) return `First pitch in ${minutes}m`;
  const hours = Math.floor(minutes / 60);
  const remainder = minutes % 60;
  return `First pitch in ${hours}h${remainder ? ` ${remainder}m` : ''}`;
}

export function freshnessLabel(generatedAt: string, now: number): string {
  const generated = Date.parse(generatedAt);
  if (!Number.isFinite(generated)) return 'Freshness unknown';
  const minutes = Math.max(0, Math.round((now - generated) / 60_000));
  if (minutes < 60) return `Updated ${minutes}m ago`;
  return `Updated ${Math.round(minutes / 60)}h ago`;
}

export function evidenceLabel(source: LoadedSlate['source']): string {
  if (source === 'network') return 'Official feed';
  if (source === 'cache') return 'Verified device copy';
  return 'Labeled sample fixture';
}

export function uncertaintyLabel(state: InstrumentState): string {
  if (state.label === 'VERIFIED FORECAST') return 'Verified sourced forecast';
  if (state.label === 'OBSERVED') return 'Verified observation inputs';
  if (state.label === 'PROJECTED') return 'Weather verified; lineup uncertainty remains';
  if (state.label === 'ROOF') return 'Outdoor physics suspended';
  if (state.label === 'SOURCE UNVERIFIED') return 'Weather provenance is incomplete';
  if (state.label === 'DATA CONFLICT') return 'Conflicting feed rows withheld';
  return 'Input coverage incomplete';
}

export function lineupEvidenceLabel(game: Game): string {
  if (!game.has_lineups) return 'not available';
  const label = (value: unknown): string => typeof value === 'string' && value.trim()
    ? value.trim().toLowerCase()
    : 'status unknown';
  return `${label(game.away_lineup_status)} / ${label(game.home_lineup_status)}`;
}
