export type SlateFilter = 'all' | 'open' | 'roof' | 'incomplete';
export type SlateSort = 'edge' | 'time' | 'wind' | 'venue';

export interface SlateViewState {
  focusGamePk: number | null;
  compareGamePks: number[];
  filter: SlateFilter;
  sort: SlateSort;
  ledger: boolean;
}

const filters = new Set<SlateFilter>(['all', 'open', 'roof', 'incomplete']);
const sorts = new Set<SlateSort>(['edge', 'time', 'wind', 'venue']);

function gamePk(value: string | null): number | null {
  if (!value || !/^\d+$/.test(value)) return null;
  const parsed = Number(value);
  return Number.isSafeInteger(parsed) && parsed > 0 ? parsed : null;
}

export function parseSlateState(hash: string): SlateViewState {
  const query = hash.includes('?') ? hash.slice(hash.indexOf('?') + 1) : '';
  const params = new URLSearchParams(query);
  const compareGamePks = Array.from(new Set(
    (params.get('compare') ?? '').split(',').map((value) => gamePk(value)).filter((value): value is number => value != null),
  )).slice(0, 4);
  const filter = params.get('filter') as SlateFilter | null;
  const sort = params.get('sort') as SlateSort | null;
  return {
    focusGamePk: gamePk(params.get('focus')),
    compareGamePks,
    filter: filter && filters.has(filter) ? filter : 'all',
    sort: sort && sorts.has(sort) ? sort : 'edge',
    ledger: params.get('view') === 'ledger',
  };
}

export function slateStateHash(state: SlateViewState): string {
  const params = new URLSearchParams();
  if (state.focusGamePk != null) params.set('focus', String(state.focusGamePk));
  if (state.compareGamePks.length) params.set('compare', state.compareGamePks.slice(0, 4).join(','));
  if (state.filter !== 'all') params.set('filter', state.filter);
  if (state.sort !== 'edge') params.set('sort', state.sort);
  if (state.ledger) params.set('view', 'ledger');
  const query = params.toString();
  return query ? `#/?${query}` : '#/';
}
