<script lang="ts">
  import { now } from '../lib/clock';
  import { evidenceLabel, freshnessLabel, lineupEvidenceLabel, movementLabel, uncertaintyLabel } from '../lib/decision';
  import { factor, instrumentState, readingPublished, signed, weatherBasisLabel, weatherReceiptDetail, weatherTrusted } from '../lib/format';
  import { marketDisplay, type LoadedMarket } from '../lib/market';
  import type { DashboardPayload, Game, LoadedSlate } from '../lib/types';
  import InstrumentState from './InstrumentState.svelte';

  export let games: Game[];
  export let focusGamePk: number | null = null;
  export let compareGamePks: number[] = [];
  export let payload: DashboardPayload;
  export let source: LoadedSlate['source'];
  export let stale = false;
  export let market: LoadedMarket | null = null;
  export let onpin: (gamePk: number) => void = () => {};
  export let onselect: (gamePk: number) => void = () => {};
  export let onremove: (gamePk: number) => void = () => {};
  export let onclear: () => void = () => {};

  let copied = false;
  let copyTimer: ReturnType<typeof setTimeout> | null = null;

  $: focus = focusGamePk == null ? null : games.find((game) => game.game_pk === focusGamePk) ?? null;
  $: compared = compareGamePks
    .map((gamePk) => games.find((game) => game.game_pk === gamePk))
    .filter((game): game is Game => Boolean(game));
  $: focusState = focus ? instrumentState(focus) : null;

  const marketLabel = (game: Game): string => {
    const display = marketDisplay(market, game.game_pk, payload.date, $now);
    if (!display || display.total.posted_total == null || display.freshness === 'stale' || display.freshness === 'unknown') return 'not available';
    return `${display.total.posted_total.toFixed(1)} · ${display.sample ? 'sample' : display.freshness}`;
  };
  const airLabel = (game: Game): string => !weatherTrusted(game) ? 'source unverified'
    : game.air_density_index == null || !Number.isFinite(game.air_density_index)
    ? 'not available'
    : `${game.air_density_index.toFixed(1)} index`;
  $: showMarket = compared.some((game) => marketLabel(game) !== 'not available');

  async function copyLink() {
    try {
      await navigator.clipboard.writeText(location.href);
      copied = true;
      if (copyTimer) clearTimeout(copyTimer);
      copyTimer = setTimeout(() => copied = false, 1800);
    } catch {
      copied = false;
    }
  }
</script>

<section class="comparison-tray" class:has-focus={focus !== null} aria-labelledby="inspector-title">
  <header class="comparison-tray__header">
    <div>
      <p class="eyebrow">Scorer's desk</p>
      <h2 id="inspector-title">Ballpark Comparison</h2>
    </div>
    <p>{compared.length}/4 comparison pins</p>
  </header>

  {#if focus && focusState}
    <div class="signal-inspector">
      <div class="signal-inspector__identity">
        <span class="inspector-index">SELECTED</span>
        <h3>{focus.away_team} <i>at</i> {focus.home_team}</h3>
        <p>{focus.venue}</p>
      </div>
      <dl class="inspector-numbers">
        <div><dt>Park baseline</dt><dd>{factor(focus.seasonal_pf_runs)}</dd><small>scoring factor</small></div>
        <div><dt>Game-time projection</dt><dd>{factor(readingPublished(focus) ? focus.daily_pf_runs : null)}</dd><small>scoring factor</small></div>
        <div class="inspector-movement"><dt>Movement</dt><dd>{readingPublished(focus) ? movementLabel(focus) : 'withheld'}</dd><small>factor ratio, not runs</small></div>
      </dl>
      <div class="inspector-actions">
        <button class:active={compareGamePks.includes(focus.game_pk)} type="button" onclick={() => onpin(focus!.game_pk)}>
          {compareGamePks.includes(focus.game_pk) ? 'Pinned for comparison' : 'Pin for comparison'}
        </button>
        <a href={`#/game/${focus.game_pk}`}>Open full station →</a>
      </div>
      <dl class="evidence-receipt" aria-label="Selected game evidence receipt">
        <div><dt>Feed</dt><dd>{evidenceLabel(source)}</dd></div>
        <div><dt>Freshness</dt><dd class:receipt-alert={stale}>{freshnessLabel(payload.generated_at, $now)}{stale ? ' · stale' : ''}</dd></div>
        <div><dt>Evidence</dt><dd><InstrumentState state={focusState} /> <span>{uncertaintyLabel(focusState)}</span></dd></div>
        <div><dt>Snapshot basis</dt><dd>{weatherTrusted(focus) ? `${weatherBasisLabel(focus)} · ${weatherReceiptDetail(focus)}` : 'Published model snapshot · source provisional'}</dd></div>
      </dl>
    </div>
  {:else}
    <button class="inspector-empty" type="button" onclick={() => games[0] && onselect(games[0].game_pk)}>
      <span>Select a ballpark card, Wind Field station, or Ledger row.</span>
      <strong>Inspect the official reading →</strong>
    </button>
  {/if}

  {#if compared.length}
    <div class="comparison-board">
      <header>
        <div><p class="eyebrow">Pinned readings</p><h3>{compared.length < 2 ? 'Add one more game to compare' : `${compared.length}-game comparison`}</h3></div>
        <div class="comparison-actions"><button type="button" onclick={copyLink}>{copied ? 'Link copied' : 'Copy comparison link'}</button><button type="button" onclick={onclear}>Clear</button></div>
      </header>
      <!-- svelte-ignore a11y_no_noninteractive_tabindex -- keyboard users need a focusable horizontal table scroller -->
      <div class="comparison-scroll" role="region" tabindex="0" aria-label="Pinned game comparison table">
        <table>
          <thead><tr><th>READING</th>{#each compared as game (game.game_pk)}<th><button type="button" onclick={() => onselect(game.game_pk)}>{game.away_team} at {game.home_team}</button><button class="compare-remove" type="button" onclick={() => onremove(game.game_pk)} aria-label={`Remove ${game.away_team} at ${game.home_team} from comparison`}>×</button></th>{/each}</tr></thead>
          <tbody>
            <tr><th>Park baseline</th>{#each compared as game}<td>{factor(game.seasonal_pf_runs)}</td>{/each}</tr>
            <tr><th>Game-time factor</th>{#each compared as game}<td>{factor(readingPublished(game) ? game.daily_pf_runs : null)}</td>{/each}</tr>
            <tr class="comparison-signal"><th>Movement</th>{#each compared as game}<td>{readingPublished(game) ? movementLabel(game) : 'withheld'}</td>{/each}</tr>
            <tr><th>Carry / crosswind</th>{#each compared as game}<td class="wind-derived">{!weatherTrusted(game) ? 'source unverified' : Boolean(game.dome_active) ? 'roof suspended' : `${signed(game.wind_carry_mph, 1)} / ${signed(game.wind_cross_mph ?? null, 1)} mph`}</td>{/each}</tr>
            <tr><th>Air density</th>{#each compared as game}<td>{airLabel(game)}</td>{/each}</tr>
            <tr><th>Lineups</th>{#each compared as game}<td>{lineupEvidenceLabel(game)}</td>{/each}</tr>
            {#if showMarket}<tr><th>Market total</th>{#each compared as game}<td>{marketLabel(game)}</td>{/each}</tr>{/if}
            <tr><th>Evidence state</th>{#each compared as game}<td>{uncertaintyLabel(instrumentState(game))}</td>{/each}</tr>
            <tr><th>Model / freshness</th>{#each compared as _game}<td>{payload.model_version} · {freshnessLabel(payload.generated_at, $now)}</td>{/each}</tr>
          </tbody>
        </table>
      </div>
    </div>
  {/if}
</section>
