// The single source of truth for the card's run-scoring meaning. Every percentage is derived from the
// two real factors — the mislabeled `pf_weather_delta_runs` (a factor delta) is never used and never
// shown as "runs". The verdict, the scale marker, and the "Largest movement" sort all read from here,
// so they can never disagree.

export type VerdictStrength = 'none' | 'slight' | 'strong' | 'extreme';
export type VerdictDirection = 'increase' | 'decrease' | 'baseline';

export interface Meaning {
  seasonal: number | null;
  daily: number | null;
  baselinePct: number | null;    // (seasonal - 1) * 100  — vs MLB average
  projectionPct: number | null;  // (daily - 1) * 100     — vs MLB average
  adjustmentPct: number | null;  // (daily / seasonal - 1) * 100 — the model's game-time step; null if no baseline
  verdict: { strength: VerdictStrength; direction: VerdictDirection; label: string };
  markerFraction: number | null; // 0..1 position of adjustmentPct on a -30..+30 scale
}

const clamp01 = (x: number) => Math.max(0, Math.min(1, x));
const num = (v: unknown): number | null => (typeof v === 'number' && Number.isFinite(v) ? v : null);

function verdictFor(adj: number | null): Meaning['verdict'] {
  if (adj == null) return { strength: 'none', direction: 'baseline', label: 'PROJECTION ONLY' };
  const mag = Math.abs(adj);
  if (mag < 3) return { strength: 'none', direction: 'baseline', label: 'NEAR PARK BASELINE' };
  const strength: VerdictStrength = mag > 15 ? 'extreme' : mag >= 8 ? 'strong' : 'slight';
  const direction: VerdictDirection = adj > 0 ? 'increase' : 'decrease';
  const word = direction === 'increase' ? 'INCREASE' : 'DECREASE';
  return { strength, direction, label: `${strength.toUpperCase()} ${word} IN PROJECTED SCORING` };
}

export function meaning(seasonal: unknown, daily: unknown): Meaning {
  const s0 = num(seasonal);
  const s = s0 != null && s0 > 0 ? s0 : null;
  const d = num(daily);
  const baselinePct = s != null ? Math.round((s - 1) * 100) : null;
  const projectionPct = d != null ? Math.round((d - 1) * 100) : null;
  const adjustmentPct = s != null && d != null ? Math.round((d / s - 1) * 100) : null;
  return {
    seasonal: s,
    daily: d,
    baselinePct,
    projectionPct,
    adjustmentPct,
    // No daily factor = nothing projected at all (e.g. an INCOMPLETE game). Seasonal-only = we have the
    // projection but can't split the baseline out — those are different, honest states.
    verdict: d == null
      ? { strength: 'none', direction: 'baseline', label: 'NO PROJECTION YET' }
      : verdictFor(adjustmentPct),
    markerFraction: adjustmentPct != null ? clamp01((adjustmentPct + 30) / 60) : null,
  };
}

/** Plain, model-based consequence sentence. Uses the caller-supplied baseline label (window unverified). */
export function consequence(m: Meaning, baselineLabel: string): string {
  if (m.adjustmentPct == null) {
    return `Showing the projection only — game-time conditions can't be split from ${baselineLabel} yet.`;
  }
  if (m.verdict.direction === 'baseline') {
    return `Game-time conditions are near ${baselineLabel} — this plays about like a normal day here.`;
  }
  const dir = m.verdict.direction === 'increase' ? 'above' : 'below';
  return `Game-time conditions put projected scoring about ${Math.abs(m.adjustmentPct)}% ${dir} ${baselineLabel}.`;
}
