// The Market Read — the single source of truth for how the instrument reacts to a posted total.
//
// Honesty architecture (mirrors meaning.ts): the frontend owns two residuals — the model's
// game-time adjustment vs its own park baseline (meaning().adjustmentPct) and the market's
// de-vigged lean vs its own posted number. The reaction compares DIRECTION ONLY. It never converts
// a factor into a run count, never grades conviction into a pick, and never reads the pick-shaped
// legacy fields (edge/recommendation/win_prob_home). Raw sportsbook prices never reach this module —
// only the de-vigged over probability does. Phase 2 adds one Engine-computed row; the grammar here
// does not change.

import type { Meaning } from './meaning';
import type { MarketFreshness } from './types';

export const JUICE_FLAT_PTS = 1.5; // |over% − 50| < 1.5 → flat (routine vig shading, not signal)
export const JUICE_STRONG_PTS = 3.5; // |over% − 50| ≥ 3.5 → strong lean (≈ −130, the practical ceiling)
export const MOVE_MIN_RUNS = 0.5; // books move totals in half-runs

export type LeanSide = 'over' | 'under' | 'flat';
export type LeanStrength = 'flat' | 'lean' | 'strong';
export type Arrow = '↑' | '↓' | '—';
export type MoveRelation = 'toward' | 'against' | 'flat-air' | 'unchanged';
export type Alignment =
  | 'no-market'
  | 'suspended'
  | 'reference-only'
  | 'both-quiet'
  | 'market-only'
  | 'conditions-only'
  | 'aligned'
  | 'split';

/** Structurally a MarketGameTotal minus game_pk — pass a MarketGameTotal directly. */
export interface MarketReadInput {
  posted_total: number | null;
  over_implied_prob: number | null;
  total_open?: number | null;
  book_count?: number | null;
  park_adjusted_total?: number | null;
  runs_edge?: number | null;
}

export interface MarketRead {
  alignment: Alignment;
  postedTotal: number | null;
  overPct: number | null; // rounded for display
  underPct: number | null;
  lean: { side: LeanSide; strength: LeanStrength } | null;
  freshness: MarketFreshness | null;
  ageMinutes: number | null;
  move: { from: number; to: number; delta: number; relation: MoveRelation } | null;
  glyph: { air: Arrow; market: Arrow } | null;
  label: string; // ALL-CAPS verdict line, neutral ink; '' for no-market
  summary: string; // card one-liner suffix
  sentence: string; // detail consequence, model-based, no advice verbs
  engineRef: { parkAdjusted: number; posted: number; runsEdge: number } | null; // phase 2
}

const num = (v: unknown): number | null => (typeof v === 'number' && Number.isFinite(v) ? v : null);
const round1 = (x: number) => Math.round(x * 10) / 10;
const totalText = (t: number | null) => (t == null ? '—' : String(t));
const firmly = (s: LeanStrength) => (s === 'strong' ? 'firmly ' : '');

export function marketRead(
  mkt: MarketReadInput | null | undefined,
  m: Meaning,
  freshness: MarketFreshness | null,
  ageMinutes: number | null,
): MarketRead {
  const posted = mkt ? num(mkt.posted_total) : null;
  const overProb = mkt ? num(mkt.over_implied_prob) : null;
  const openTotal = mkt ? num(mkt.total_open) : null;

  const overPct = overProb != null ? Math.round(overProb * 100) : null;
  const underPct = overPct != null ? 100 - overPct : null;

  // Market lean, computed on the raw de-vigged value (display is rounded separately).
  const ptsRaw = overProb != null ? overProb * 100 - 50 : null;
  let lean: MarketRead['lean'] = null;
  if (ptsRaw != null) {
    const mag = Math.abs(ptsRaw);
    const strength: LeanStrength = mag < JUICE_FLAT_PTS ? 'flat' : mag >= JUICE_STRONG_PTS ? 'strong' : 'lean';
    const side: LeanSide = strength === 'flat' ? 'flat' : ptsRaw > 0 ? 'over' : 'under';
    lean = { side, strength };
  }
  const leanFlat = lean == null || lean.side === 'flat';

  // The model's residual (from the existing Meaning). "Moved" = a real slight/strong/extreme read.
  const airHasProjection = m.adjustmentPct != null;
  const airMoved = airHasProjection && m.verdict.direction !== 'baseline';
  const airUp = m.verdict.direction === 'increase';
  const adjMag = m.adjustmentPct != null ? Math.abs(m.adjustmentPct) : null;

  // Line move — a secondary fact row, never a verdict.
  let move: MarketRead['move'] = null;
  if (posted != null && openTotal != null) {
    const delta = round1(posted - openTotal);
    let relation: MoveRelation;
    if (Math.abs(delta) < MOVE_MIN_RUNS) relation = 'unchanged';
    else if (!airMoved) relation = 'flat-air';
    else relation = delta > 0 === airUp ? 'toward' : 'against';
    move = { from: openTotal, to: posted, delta, relation };
  }

  // Phase-2 Engine reference (rendered only; the frontend never computes runs).
  const parkAdj = mkt ? num(mkt.park_adjusted_total) : null;
  const runsEdge = mkt ? num(mkt.runs_edge) : null;
  const engineRef =
    parkAdj != null && posted != null && runsEdge != null
      ? { parkAdjusted: parkAdj, posted, runsEdge }
      : null;

  // State machine — precedence order.
  let alignment: Alignment;
  if (posted == null) alignment = 'no-market';
  else if (freshness === 'stale') alignment = 'suspended';
  else if (!airHasProjection) alignment = 'reference-only';
  else if (overProb == null) alignment = 'reference-only';
  else if (leanFlat && !airMoved) alignment = 'both-quiet';
  else if (leanFlat && airMoved) alignment = 'conditions-only';
  else if (!leanFlat && !airMoved) alignment = 'market-only';
  else alignment = airUp === (lean!.side === 'over') ? 'aligned' : 'split';

  const hasGlyph = !(alignment === 'no-market' || alignment === 'suspended' || alignment === 'reference-only');
  const air: Arrow = airMoved ? (airUp ? '↑' : '↓') : '—';
  const marketArrow: Arrow = lean && lean.side !== 'flat' ? (lean.side === 'over' ? '↑' : '↓') : '—';
  const glyph = hasGlyph ? { air, market: marketArrow } : null;

  const T = totalText(posted);
  const side = lean && lean.side !== 'flat' ? lean.side : 'over';
  const ageHrs = ageMinutes != null ? Math.max(1, Math.round(ageMinutes / 60)) : null;
  const dir = airUp ? 'above' : 'below';

  let label: string;
  let summary: string;
  let sentence: string;
  switch (alignment) {
    case 'aligned':
      label = `AIR AND MARKET POINT THE SAME WAY · ${airUp ? 'UP' : 'DOWN'}`;
      summary = `juice leans ${firmly(lean!.strength)}${side} · same way as game-time air`;
      sentence = `Game-time conditions read about ${adjMag}% ${dir} this park's baseline, and the de-vigged juice on ${T} sits to the ${side} — the instrument and the posted number point the same way. Neither reading validates the other.`;
      break;
    case 'split':
      label = 'AIR AND MARKET POINT OPPOSITE WAYS';
      summary = `juice leans ${firmly(lean!.strength)}${side} · opposite game-time air`;
      sentence = `Game-time conditions read about ${adjMag}% ${dir} this park's baseline while the juice on ${T} leans ${side} — pointing opposite ways. The market prices pitching, lineups and bullpens; this instrument only measures air.`;
      break;
    case 'conditions-only':
      label = 'MARKET FLAT ON THE NUMBER · AIR IS NOT';
      summary = 'juice flat on the number';
      sentence = `The model reads game-time conditions about ${adjMag}% ${dir} this park's baseline; the juice on ${T} is balanced. That is a disagreement, not a verdict — the market prices many inputs this instrument does not measure.`;
      break;
    case 'market-only':
      label = `MARKET LEANS ${side.toUpperCase()} · AIR NEAR BASELINE`;
      summary = `juice leans ${firmly(lean!.strength)}${side} · air near baseline`;
      sentence = `The juice on ${T} leans ${firmly(lean!.strength)}${side}. Game-time air sits near this park's baseline, so whatever the market is pricing, it is not the weather this instrument measures.`;
      break;
    case 'both-quiet':
      label = 'MARKET FLAT · AIR NEAR BASELINE';
      summary = 'juice flat · air near baseline';
      sentence = `The juice on ${T} is balanced and game-time air is near this park's baseline — neither the market nor the instrument reads anything unusual here.`;
      break;
    case 'reference-only':
      label = 'MARKET NUMBER ONLY · NOTHING TO COMPARE';
      if (overPct == null) {
        summary = 'juice not captured';
        sentence = `A market total of ${T} is posted; its pricing balance was not captured, so no lean is read.`;
      } else {
        summary = 'no projection to compare';
        sentence = `A market total of ${T} is posted, but no game-time projection exists yet, so there is nothing to compare it against.`;
      }
      break;
    case 'suspended':
      label = 'MARKET READ SUSPENDED · ODDS STALE';
      summary = 'odds stale';
      sentence = `This line was captured ${ageHrs != null ? `${ageHrs}h` : 'some time'} ago and has likely moved. The number is shown for the record; no comparison is made against a stale line.`;
      break;
    default: // no-market
      label = '';
      summary = 'not posted for this game';
      sentence = 'No market total is posted for this game yet.';
  }

  return {
    alignment,
    postedTotal: posted,
    overPct,
    underPct,
    lean,
    freshness,
    ageMinutes,
    move,
    glyph,
    label,
    summary,
    sentence,
    engineRef,
  };
}
