<script lang="ts">
  import { onMount } from 'svelte';
  import InstrumentState from '../components/InstrumentState.svelte';
  import MarketBlock from '../components/MarketBlock.svelte';
  import ParkWindDiagram from '../components/ParkWindDiagram.svelte';
  import TrajectoryTheater from '../components/TrajectoryTheater.svelte';
  import { now } from '../lib/clock';
  import { evidenceLabel, freshnessLabel, lineupEvidenceLabel, movementLabel, uncertaintyLabel } from '../lib/decision';
  import {
    factor,
    factorMeaning,
    gameTime,
    instrumentState,
    readingPublished,
    signed,
    weather,
    weatherBasisLabel,
    weatherReceiptBasis,
    weatherReceiptDetail,
    weatherSourceLabel,
    weatherTrusted,
  } from '../lib/format';
  import { loadStaticGeometry, parkGeometryForTeam, type StaticGeometry } from '../lib/geometry';
  import { marketDisplay, type LoadedMarket } from '../lib/market';
  import { meaning } from '../lib/meaning';
  import type { Game, LoadedSlate } from '../lib/types';

  export let game: Game | undefined;
  export let fixture = false;
  export let market: LoadedMarket | null = null;
  export let slateDate: string | null = null;
  export let generatedAt = '';
  export let source: LoadedSlate['source'] = 'fixture';
  export let stale = false;

  $: runMeaning = game ? factorMeaning(game.daily_pf_runs) : null;
  $: marketMd = game ? marketDisplay(market, game.game_pk, slateDate, $now) : null;

  let rawGeometry: StaticGeometry | null = null;
  onMount(() => { loadStaticGeometry().then((value) => { rawGeometry = value; }); });

  $: parkGeometry = game ? parkGeometryForTeam(rawGeometry, game.home_team) : null;
  $: state = game ? instrumentState(game) : null;
  $: weatherMultiplier = game?.seasonal_pf_runs && game.daily_pf_runs != null
    ? game.daily_pf_runs / game.seasonal_pf_runs
    : null;
  $: hasPublishedReading = game ? readingPublished(game) : false;
  $: hasTrustedWeather = game ? weatherTrusted(game) : false;
  $: receiptBasis = game ? weatherReceiptBasis(game) : 'unknown';
  $: receiptDetail = game ? weatherReceiptDetail(game) : 'source or time receipt incomplete';
  $: conditionsTitle = receiptBasis === 'forecast' ? 'Verified Forecast'
    : receiptBasis === 'observation' ? 'Observed Conditions'
    : receiptBasis === 'indoor' ? 'Roof-Controlled Conditions'
    : 'Weather Conditions';
  $: hasWeatherInputs = game ? [game.temperature_f, game.humidity_pct, game.wind_carry_mph, game.wind_cross_mph, game.air_density_index]
    .some((value) => typeof value === 'number' && Number.isFinite(value)) : false;
  $: contextCount = game ? Number(Boolean(game.starter_context)) + Number(Boolean(game.injury_war_context)) : 0;
</script>

{#if !game}
  <section class="not-found"><p class="eyebrow">Station not found</p><h1>This game is not on the loaded slate.</h1><a class="button-link" href="#/">Return to The Slate</a></section>
{:else}
  <a class="back-link" href="#/">← The Slate</a>
  <header class="detail-header">
    <div>
      <p class="eyebrow">{gameTime(game.game_time)} · GAME {game.game_pk}</p>
      <h1><span>{game.away_team}</span><i>at</i><span>{game.home_team}</span></h1>
      <p>{game.away_pitcher ?? 'Starter not posted'} <i>vs</i> {game.home_pitcher ?? 'Starter not posted'}</p>
    </div>
    {#if state}<div class="detail-state"><InstrumentState {state} showReason /></div>{/if}
  </header>

  <ParkWindDiagram {game} staticGeometry={parkGeometry} trusted={hasTrustedWeather} />

  <section class="decomposition" aria-labelledby="decomposition-title">
    <div class="section-kicker-row"><div><p class="eyebrow">How the game-time projection is built</p><h2 id="decomposition-title">Decomposition Ladder</h2></div><span class="model-stamp">{(game.model_run_at ?? generatedAt) || 'RUN TIME NOT EMITTED'}</span></div>
    <ol>
      <li><span class="rung-index">01</span><div><span>Park scoring baseline</span><small>this venue’s comparison point</small></div><strong>{factor(game.seasonal_pf_runs)}</strong></li>
      <li class:unavailable={!hasPublishedReading || weatherMultiplier == null}><span class="rung-index">02</span><div><span>× Game-time conditions</span><small>{hasPublishedReading ? hasTrustedWeather ? receiptDetail : 'published model input · source provisional' : state?.reason}</small></div><strong>{factor(hasPublishedReading ? weatherMultiplier : null)}</strong></li>
      <li class="final-rung" class:unavailable={!hasPublishedReading || game.daily_pf_runs == null}><span class="rung-index">03</span><div><span>Game-time scoring factor</span><small>{hasPublishedReading ? `${movementLabel(game)}${runMeaning ? ` · ${runMeaning.text} vs MLB average` : ''}${hasTrustedWeather ? '' : ' · provisional source'}` : 'withheld for incomplete or conflicting data'}</small></div><strong>{factor(hasPublishedReading ? game.daily_pf_runs : null)}</strong></li>
    </ol>
  </section>

  {#if state}
    <section class="detail-receipt" aria-labelledby="detail-receipt-title">
      <header><p class="eyebrow">Evidence receipt</p><h2 id="detail-receipt-title">What supports this reading</h2></header>
      <dl>
        <div><dt>Feed</dt><dd>{evidenceLabel(source)}</dd></div>
        <div><dt>Freshness</dt><dd class:receipt-alert={stale}>{freshnessLabel(generatedAt, $now)}{stale ? ' · stale' : ''}</dd></div>
        <div><dt>Evidence state</dt><dd>{uncertaintyLabel(state)}</dd></div>
        <div><dt>Lineups</dt><dd>{lineupEvidenceLabel(game)}</dd></div>
        <div><dt>Weather source</dt><dd>{weatherSourceLabel(game)}<span> · {receiptDetail}</span></dd></div>
        <div><dt>Snapshot basis</dt><dd>{weatherBasisLabel(game)}</dd></div>
      </dl>
    </section>
  {/if}

  <MarketBlock display={marketMd} m={meaning(game.seasonal_pf_runs, game.daily_pf_runs)} />

  {#if hasTrustedWeather && hasWeatherInputs}<section class="observed-station" aria-labelledby="conditions-title">
    <div><p class="eyebrow">Air station</p><h2 id="conditions-title">{conditionsTitle}</h2></div>
    <dl>
      {#if game.temperature_f != null}<div><dt>Temperature</dt><dd>{weather(game.temperature_f, '°F')}</dd></div>{/if}
      {#if game.humidity_pct != null}<div><dt>Humidity</dt><dd>{weather(game.humidity_pct, '%')}</dd></div>{/if}
      {#if game.wind_carry_mph != null}<div><dt>Wind carry</dt><dd>{signed(game.wind_carry_mph, 1)} mph</dd></div>{/if}
      {#if game.wind_cross_mph != null}<div><dt>Crosswind</dt><dd>{signed(game.wind_cross_mph, 1)} mph</dd></div>{/if}
      {#if game.air_density_index != null}<div><dt>Air density</dt><dd>{game.air_density_index.toFixed(1)}</dd></div>{/if}
    </dl>
  </section>{/if}

  {#if contextCount}<section class="coverage-disclosure" aria-labelledby="coverage-title">
    <details>
      <summary><span><small class="eyebrow">Published context</small><strong id="coverage-title">Supplemental game notes</strong></span><span>{contextCount} {contextCount === 1 ? 'note' : 'notes'} · open</span></summary>
      <div class="coverage-grid">
        {#if game.starter_context}<section><p class="eyebrow">Starter context</p><h3>Starter Matchup</h3><p>{game.starter_context}</p></section>{/if}
        {#if game.injury_war_context}<section><p class="eyebrow">Availability context</p><h3>Injuries &amp; Player Value</h3><p>{game.injury_war_context}</p></section>{/if}
      </div>
    </details>
  </section>{/if}

  {#if game.trajectories?.length}<TrajectoryTheater trajectories={game.trajectories} {fixture} />{/if}
{/if}
