<script lang="ts">
  import { onMount, tick } from 'svelte';
  import { track } from '../lib/telemetry';

  let theme: 'day' | 'night' = 'day';

  function apply(next: 'day' | 'night') {
    theme = next;
    document.documentElement.dataset.theme = next;
    document.querySelector('meta[name="theme-color"]')?.setAttribute('content', next === 'day' ? '#faf8f5' : '#0e1215');
    try { localStorage.setItem('prestige-theme', next); } catch { /* private mode */ }
  }

  function toggle() {
    const next = theme === 'day' ? 'night' : 'day';
    const reduce = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    const transitionDocument = document as Document & {
      startViewTransition?: (callback: () => void | Promise<void>) => unknown;
    };
    const swap = async () => {
      apply(next);
      await tick();
      // Share canvases redraw from the theme mutation; let that microtask paint before
      // the new View Transition snapshot is captured.
      await new Promise<void>((resolve) => requestAnimationFrame(() => resolve()));
    };

    if (!reduce && transitionDocument.startViewTransition) {
      transitionDocument.startViewTransition(swap);
    } else {
      void swap();
    }
    track('theme_change', { theme: next });
  }

  onMount(() => {
    const current = document.documentElement.dataset.theme;
    apply(current === 'night' ? 'night' : 'day');
  });
</script>

<button class="theme-toggle quiet-button" type="button" onclick={toggle} aria-label={`Switch to ${theme === 'day' ? 'night' : 'day'} game lighting`}>
  <span class="theme-icon" aria-hidden="true">{theme === 'day' ? '◐' : '◑'}</span>
  <span>{theme === 'day' ? 'Day game' : 'Night game'}</span>
</button>
