// Motion primitives (FE-7).
//
// The doctrine: "motion only encodes physics or state change — every animation is a
// measurement being demonstrated." Before FE-7 the app violated its own rule: wind
// streams animated at four hard-coded rates keyed off the stream's array index, and
// trajectory arcs drew on an authored ease-out. Both looked like physics and were not.
// Everything here derives timing from a MEASURED number, or returns null so the mark
// renders honestly still.

import type { Point } from './types';

/** A 10 mph carry completes one wind-flow cycle per second; faster wind, shorter period. */
const SECONDS_PER_CYCLE_AT_10_MPH = 1;
/** Below this the air is calm: it must not drift at all rather than drift slowly. */
const CALM_MPH = 0.5;

/**
 * Seconds per wind-flow cycle, derived from the measured carry speed.
 * `null` means "do not animate": calm air, absent wind, or a suspended (domed) roof.
 * Direction is handled by the diagram's rotation, so only speed is encoded here.
 */
export function windPeriodSeconds(carryMph: number | null | undefined): number | null {
  if (carryMph == null || !Number.isFinite(carryMph)) return null;
  const speed = Math.abs(carryMph);
  if (speed < CALM_MPH) return null;
  const period = (SECONDS_PER_CYCLE_AT_10_MPH * 10) / speed;
  // Clamp only to keep the extremes renderable — a 25 mph carry should look violent.
  return Math.round(Math.min(8, Math.max(0.3, period)) * 100) / 100;
}

/** Length of a polyline in the coordinate space it is drawn in. */
export function polylineLength(points: Point[]): number {
  let total = 0;
  for (let i = 1; i < points.length; i += 1) {
    total += Math.hypot(points[i].x - points[i - 1].x, points[i].y - points[i - 1].y);
  }
  return total;
}

/**
 * Draw speed shared by every trajectory arc (SVG units per second). Because both the
 * neutral and tonight arcs are drawn at ONE speed, the tonight ball is still being drawn
 * after the neutral one has landed — that extra time IS the extra carry. Nothing is eased.
 */
export const DRAW_UNITS_PER_SECOND = 300;

/** Dash length + duration for an arc, so duration is proportional to distance flown. */
export function drawFlight(points: Point[]): { length: number; seconds: number } {
  const length = polylineLength(points);
  return { length, seconds: Math.round((length / DRAW_UNITS_PER_SECOND) * 1000) / 1000 };
}
