<script lang="ts">
  import type { Meaning } from '../lib/meaning';
  import { consequence } from '../lib/meaning';
  export let m: Meaning;
  export let baselineLabel = "this park's baseline";
  const pct = (v: number | null) => (v == null ? '—' : `${v > 0 ? '+' : ''}${v}%`);
  $: dir = m.verdict.direction;
</script>

<div class="meaning">
  <div class="verdict dir-{dir}"><span class="v-dot" aria-hidden="true"></span>{m.verdict.label}</div>

  {#if m.daily == null}
    <p class="m-conseq">The game-time factor isn’t in yet — nothing is projected for this game.</p>
  {:else}
  {#if m.markerFraction != null}
    <div class="m-scale" role="img" aria-label={`Game-time adjustment ${pct(m.adjustmentPct)} versus ${baselineLabel}`}>
      <div class="m-track"></div>
      <div class="m-zero"></div>
      <span class="m-zlab">{baselineLabel}</span>
      <div class="m-mark dir-{dir}" style={`left:${(m.markerFraction * 100).toFixed(1)}%`}></div>
    </div>
  {/if}

  <p class="m-conseq">{consequence(m, baselineLabel)}</p>

  <div class="m-flow">
    <div class="m-row"><span class="m-l">This park normally</span><span class="m-v">{pct(m.baselinePct)}</span><span class="m-c">vs MLB average</span></div>
    {#if m.adjustmentPct != null}
      <div class="m-row m-bridge"><span class="m-l">↓ model adjusts</span><span class="m-v">{pct(m.adjustmentPct)}</span><span class="m-c">for game-time conditions</span></div>
    {/if}
    <div class="m-row m-result"><span class="m-l">Game-time projection</span><span class="m-v">{pct(m.projectionPct)}</span><span class="m-c">vs MLB average</span></div>
  </div>

  {#if m.seasonal != null && m.daily != null}
    <details class="m-calc">
      <summary>How this was calculated</summary>
      <div class="m-calcbody">Game-time factor {m.daily.toFixed(3)} ÷ park baseline {m.seasonal.toFixed(3)} ≈ {(m.daily / m.seasonal).toFixed(3)} → {pct(m.adjustmentPct)} adjustment <span class="dim">(a factor ratio, not a count of runs)</span></div>
    </details>
  {/if}
  {/if}
</div>
