<script lang="ts">
  import { movementPct } from '../lib/decision';
  import { edgeFade } from '../lib/edgeFade';
  import { gameTime, signed } from '../lib/format';
  import type { Game } from '../lib/types';

  export let games: Game[];
  export let focusGamePk: number | null = null;
  export let compareGamePks: number[] = [];
  export let onselect: (gamePk: number) => void = () => {};

  $: count = Math.max(1, games.length);
  $: segment = 1120 / count;
  const timeFormatter = new Intl.DateTimeFormat(undefined, { hour: 'numeric', minute: '2-digit' });
  const finite = (value: number | null | undefined): number | null => typeof value === 'number' && Number.isFinite(value) ? value : null;
  const yForMovement = (value: number | null) => value == null ? 94 : 94 - Math.max(-30, Math.min(30, value)) * 1.56;
  const carryLabel = (game: Game) => {
    if (Boolean(game.dome_active)) return 'roof';
    const carry = finite(game.wind_carry_mph);
    return carry == null ? 'n/a' : `${signed(carry, 1)} mph`;
  };
  const timeLabel = (iso: string) => {
    const date = new Date(iso);
    return Number.isNaN(date.getTime()) ? '—' : timeFormatter.format(date);
  };
</script>

<section class="wind-field" aria-labelledby="wind-field-title">
  <header class="section-kicker-row">
    <div>
      <p class="eyebrow">Whole-slate view · each park’s baseline</p>
      <h2 id="wind-field-title">Wind Field Strip</h2>
    </div>
    <div class="wind-key" aria-label="Chart legend">
      <span><i class="key-line"></i>carry wind</span>
      <span><i class="key-zero"></i>park baseline</span>
    </div>
  </header>

  <!-- svelte-ignore a11y_no_noninteractive_tabindex -- scroll region must be keyboard-focusable so keyboard users can scroll the wind field strip -->
  <div class="wind-field__scroller" role="region" tabindex="0" aria-label="Horizontal chart of scoring-factor movement by game" use:edgeFade>
    <svg viewBox="0 0 1200 190" aria-labelledby="strip-title strip-desc" preserveAspectRatio="xMidYMid meet">
      <title id="strip-title">Scoring-factor movement across today’s slate</title>
      <desc id="strip-desc">Each selectable station plots the game-time scoring-factor ratio above or below this park’s baseline, with wind carry speed and first-pitch time.</desc>
      <defs>
        <pattern id="strip-hatch" width="8" height="8" patternUnits="userSpaceOnUse" patternTransform="rotate(45)">
          <line x1="0" y1="0" x2="0" y2="8" class="hatch-line" />
        </pattern>
      </defs>
      <line x1="40" y1="62.8" x2="1160" y2="62.8" class="strip-grid" />
      <line x1="40" y1="78.4" x2="1160" y2="78.4" class="strip-grid" />
      <line x1="40" y1="109.6" x2="1160" y2="109.6" class="strip-grid" />
      <line x1="40" y1="125.2" x2="1160" y2="125.2" class="strip-grid" />
      <text x="8" y="65.8" class="strip-scale">+20%</text>
      <text x="8" y="81.4" class="strip-scale">+10%</text>
      <text x="8" y="112.6" class="strip-scale">−10%</text>
      <text x="8" y="128.2" class="strip-scale">−20%</text>
      <line x1="40" y1="94" x2="1160" y2="94" class="strip-baseline" />
      <text x="8" y="98" class="strip-zero">BASE</text>
      {#each games as game, index (game.game_pk)}
        {@const x = 40 + segment * index + segment / 2}
        {@const movement = movementPct(game)}
        {@const carry = finite(game.wind_carry_mph)}
        {@const y = yForMovement(movement)}
        {@const missing = movement == null}
        <g class:dome={Boolean(game.dome_active)} class:missing class:is-selected={focusGamePk === game.game_pk} class:is-pinned={compareGamePks.includes(game.game_pk)} transform={`translate(${x}, 0)`}>
          <a href={`#/?focus=${game.game_pk}`} class="station-link" aria-label={`Inspect ${game.away_team} at ${game.home_team}, first pitch ${gameTime(game.game_time)}`} onclick={(event) => { event.preventDefault(); onselect(game.game_pk); }}>
            <rect x={-segment / 2 + 1} y="0" width={segment - 2} height="190" class="station-hit" aria-hidden="true" />
            {#if focusGamePk === game.game_pk || compareGamePks.includes(game.game_pk)}
              <rect x={-segment / 2 + 4} y="4" width={segment - 8} height="182" class="station-selection" />
            {/if}
            {#if !Boolean(game.dome_active) && movement != null && Math.abs(movement) >= 3}
              <rect
                x={-segment / 2 + 1}
                y="30"
                width={segment - 2}
                height="110"
                class="band-tint"
                fill={movement > 0 ? 'var(--favorable-soft)' : 'var(--adverse-soft)'}
                opacity={0.18 + Math.min(1, Math.abs(movement) / 30) * 0.3}
              />
            {/if}
            {#if Boolean(game.dome_active)}
              <rect x={-segment / 2 + 1} y="30" width={segment - 2} height="110" rx="2" class="dome-band" />
            {/if}
            <line x1="0" y1="30" x2="0" y2="140" class="station-rule" />
            {#if missing}
              <rect x="-14" y="80" width="28" height="28" fill="url(#strip-hatch)" class="missing-block" />
            {:else}
              <line x1="0" y1="94" x2="0" y2={y} class="delta-stem" />
              <circle cx="0" cy={y} r="5" class="station-dot" />
              {#if !Boolean(game.dome_active) && carry != null}
                <path d={`M -18 ${y - 9} H 18 M ${carry >= 0 ? 8 : -8} ${y - 14} L ${carry >= 0 ? 18 : -18} ${y - 9} L ${carry >= 0 ? 8 : -8} ${y - 4}`} class="wind-arrow" />
              {/if}
            {/if}
            <text x="0" y="156" class="station-team">{game.away_team}·{game.home_team}</text>
            <text x="0" y="169" class="station-delta">{movement == null ? '—' : `${movement > 0 ? '+' : ''}${movement}%`}</text>
            <text x="0" y="181" class="station-time">{timeLabel(game.game_time)}</text>
            <text x="0" y="18" class="station-value">{carryLabel(game)}</text>
          </a>
        </g>
      {/each}
    </svg>
  </div>
</section>
