// The clock (FE-7).
//
// Before this, `loadSlate()` ran exactly once in onMount and `age` was reactive on a value
// that never changed again — so the age readout froze at mount and the "STALE · VERIFY
// BEFORE USE" chip was structurally incapable of ever firing in-session. Meanwhile /#/method
// publicly promises a 15-minute weather cadence the app never honoured. That is an honesty
// breach wearing a missing feature's clothes: a phone left open at a sportsbook for three
// hours still read "16m old".

import { readable } from 'svelte/store';
import { dataMode } from './config';
import { loadSlate } from './data';
import type { LoadedSlate } from './types';

const TICK_MS = 30_000;
/** The cadence the product publicly claims on /#/method. */
const REFRESH_MS = 15 * 60_000;
/** Never re-fetch more often than this, however many wake events arrive. */
const MIN_GAP_MS = 60_000;

/** Wall clock. Ticks so age and staleness are live readings rather than mount-time fossils. */
export const now = readable(Date.now(), (set) => {
  const id = setInterval(() => set(Date.now()), TICK_MS);
  return () => clearInterval(id);
});

/**
 * Re-fetch the slate on the promised cadence, and immediately when the tab comes back
 * (the pocket case: the sportsbook user re-opens the phone and must not read a stale number).
 * Gated on visible + online so we never poll in the background, and hermetic in fixture mode.
 * Re-uses `loadSlate()` untouched, so the schema firewall, cache fallback and provenance
 * labelling all still apply to every refresh.
 */
export function startSlateRefresh(apply: (slate: LoadedSlate) => void): () => void {
  if (dataMode === 'fixture' || typeof document === 'undefined') return () => {};
  let lastAt = Date.now();
  let inFlight = false;

  const refresh = async () => {
    if (inFlight) return;
    if (document.visibilityState !== 'visible' || !navigator.onLine) return;
    if (Date.now() - lastAt < MIN_GAP_MS) return;
    inFlight = true;
    lastAt = Date.now();
    try {
      apply(await loadSlate());
    } finally {
      inFlight = false;
    }
  };

  const id = setInterval(() => { void refresh(); }, REFRESH_MS);
  const wake = () => { void refresh(); };
  document.addEventListener('visibilitychange', wake);
  window.addEventListener('online', wake);

  return () => {
    clearInterval(id);
    document.removeEventListener('visibilitychange', wake);
    window.removeEventListener('online', wake);
  };
}
