// Market totals loader — a sidecar artifact (market.json) parallel to batters.json/accuracy.json.
// Odds refresh ~2×/day (morning + lineup-lock), far slower and far more time-sensitive than the
// weather payload, so freshness is computed PER ARTIFACT here rather than riding the global ribbon.

import { loadOptional } from './data';
import { dataMode } from './config';
import { fixtureMarket } from './fixture';
import type { MarketFreshness, MarketGameTotal, MarketPayload } from './types';

// Bands tuned for a ~2×/day feed: a morning line viewed early afternoon is still current. Date
// mismatch with the slate is the primary stale trigger (means the snapshot job did not run today).
export const MARKET_FRESH_MAX_H = 3; // < 3h → fresh
export const MARKET_STALE_MIN_H = 6; // Market snapshots have their own six-hour usability window.

export interface LoadedMarket {
  payload: MarketPayload;
  byGame: Map<number, MarketGameTotal>;
  source: 'network' | 'fixture';
}

export interface MarketDisplay {
  total: MarketGameTotal;
  freshness: MarketFreshness;
  ageMinutes: number | null;
  sample: boolean;
  sourceLabel: string;
  capturedAt: string;
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null;
}

export function isMarketPayload(value: unknown): value is MarketPayload {
  if (!isRecord(value)) return false;
  if (typeof value.date !== 'string' || typeof value.captured_at !== 'string') return false;
  if (typeof value.source_label !== 'string' || typeof value.provenance !== 'string') return false;
  if (!Array.isArray(value.totals)) return false;
  return value.totals.every(
    (t) => isRecord(t) && typeof t.game_pk === 'number' && (t.posted_total === null || typeof t.posted_total === 'number'),
  );
}

/** First occurrence wins on a duplicate game_pk (same philosophy as dedupeGames for the slate). */
export function indexMarket(payload: MarketPayload): Map<number, MarketGameTotal> {
  const byGame = new Map<number, MarketGameTotal>();
  for (const total of payload.totals) {
    if (!byGame.has(total.game_pk)) byGame.set(total.game_pk, total);
  }
  return byGame;
}

export interface MarketFreshnessResult {
  status: MarketFreshness;
  ageMinutes: number | null;
  ageHours: number | null;
}

export function marketFreshness(
  capturedAt: string,
  marketDate: string | null | undefined,
  slateDate: string | null | undefined,
  now: number,
): MarketFreshnessResult {
  const capturedMs = Date.parse(capturedAt);
  if (Number.isNaN(capturedMs)) return { status: 'unknown', ageMinutes: null, ageHours: null };
  const ageMinutes = Math.max(0, (now - capturedMs) / 60_000);
  const ageHours = ageMinutes / 60;
  // A snapshot dated to a different slate means today's job did not run — the line is not current.
  if (marketDate && slateDate && marketDate !== slateDate) return { status: 'stale', ageMinutes, ageHours };
  if (ageHours >= MARKET_STALE_MIN_H) return { status: 'stale', ageMinutes, ageHours };
  if (ageHours >= MARKET_FRESH_MAX_H) return { status: 'aging', ageMinutes, ageHours };
  return { status: 'fresh', ageMinutes, ageHours };
}

/** The device copy of the sample market, for the offline/fixture demo. */
export const fixtureLoadedMarket: LoadedMarket = {
  payload: fixtureMarket,
  byGame: indexMarket(fixtureMarket),
  source: 'fixture',
};

/**
 * Fetch market.json if published. Hermetic in fixture mode (like every optional artifact) — the
 * App pairs the fixture slate with `fixtureLoadedMarket` directly so live odds never join fixture
 * game_pks. Returns null when no artifact is published (a designed, calm consumer state).
 */
export async function loadMarket(): Promise<LoadedMarket | null> {
  if (dataMode === 'fixture') return null;
  const payload = await loadOptional('market.json', isMarketPayload);
  return payload ? { payload, byGame: indexMarket(payload), source: 'network' } : null;
}

/**
 * Package a single game's market for rendering, or null when there is nothing to show (no artifact,
 * or this game absent). SAMPLE data is always shown as 'fresh' (its age is meaningless) with the
 * `sample` flag set, so every reaction state is demoable offline; network data gets real freshness.
 */
export function marketDisplay(
  loaded: LoadedMarket | null,
  gamePk: number,
  slateDate: string | null,
  now: number,
): MarketDisplay | null {
  if (!loaded) return null;
  const total = loaded.byGame.get(gamePk);
  if (!total) return null;
  if (loaded.source === 'fixture') {
    return { total, freshness: 'fresh', ageMinutes: null, sample: true, sourceLabel: loaded.payload.source_label, capturedAt: loaded.payload.captured_at };
  }
  const fresh = marketFreshness(loaded.payload.captured_at, loaded.payload.date, slateDate, now);
  return { total, freshness: fresh.status, ageMinutes: fresh.ageMinutes, sample: false, sourceLabel: loaded.payload.source_label, capturedAt: loaded.payload.captured_at };
}
