<script lang="ts">
  import type { Game, ParkGeometry, Point } from '../lib/types';
  import { signed } from '../lib/format';
  import { windPeriodSeconds } from '../lib/motion';
  export let game: Game;
  export let trusted = true;
  // Vendored static geometry (FE-2), converted for this park; overrides any per-game
  // geometry in the payload. Null keeps the honest "GEOMETRY NOT PRESENT" gate.
  export let staticGeometry: ParkGeometry | null = null;

  const HOME_X = 320;
  const HOME_Y = 344;
  const PX_PER_FT = 0.64;
  const RANGE_FEET = [250, 300, 350, 400] as const;
  const DISTANCE_MARKS = [
    { index: 0, angle: -45, label: 'LF' },
    { index: 45, angle: 0, label: 'CF' },
    { index: 90, angle: 45, label: 'RF' },
  ] as const;

  const toPath = (points: Point[]) => points.length ? `M ${points.map((point) => `${point.x},${point.y}`).join(' L ')} Z` : '';
  const rangeArc = (feet: number) => {
    const radius = feet * PX_PER_FT;
    const diagonal = radius * Math.SQRT1_2;
    return `M ${HOME_X - diagonal} ${HOME_Y - diagonal} A ${radius} ${radius} 0 0 1 ${HOME_X + diagonal} ${HOME_Y - diagonal}`;
  };

  $: geometry = staticGeometry ?? game.park_geometry;
  $: wall = geometry?.wall ?? [];
  $: wallSegments = wall.length >= 3
    ? wall.slice(1, -1).map((from, index) => ({
      from,
      to: wall[index + 2],
      height: geometry?.wall_height_ft?.[index + 2] ?? 0,
    }))
    : [];
  $: distanceStamps = geometry?.wall_distance_ft?.length === 91
    ? DISTANCE_MARKS.map(({ index, angle, label }) => {
      const distance = geometry!.wall_distance_ft![index];
      const radius = distance * PX_PER_FT + 14;
      const theta = angle * Math.PI / 180;
      return {
        x: HOME_X + radius * Math.sin(theta),
        y: HOME_Y - radius * Math.cos(theta),
        text: `${label} ${Math.round(distance)}`,
      };
    })
    : [];
  $: wallHeights = (geometry?.wall_height_ft ?? []).slice(1).filter((height) => Number.isFinite(height));
  $: wallHeightMin = wallHeights.length ? Math.round(Math.min(...wallHeights)) : null;
  $: wallHeightMax = wallHeights.length ? Math.round(Math.max(...wallHeights)) : null;
  $: wind = trusted ? game.wind_carry_mph : null;
  $: cross = trusted ? game.wind_cross_mph ?? null : null;
  $: direction = Math.atan2(cross ?? 0, wind ?? 0) * 180 / Math.PI;
  $: carryVector = wind == null ? 0 : Math.min(40, Math.abs(wind) * 2.2) * Math.sign(wind);
  $: crossVector = cross == null ? 0 : Math.min(40, Math.abs(cross) * 2.2) * Math.sign(cross);
  // Drift period comes from the MEASURED carry speed — null means genuinely still air.
  $: windPeriod = windPeriodSeconds(wind);
</script>

<figure class="park-diagram" class:is-dome={Boolean(game.dome_active)}>
  <div class="diagram-heading">
    <div>
      <p class="eyebrow">Park wind diagram</p>
      <h2>{game.venue}</h2>
    </div>
    <span class="wind-readout" class:receipt-alert={!trusted}>{trusted ? `CARRY ${signed(wind, 1)}` : 'WIND WITHHELD'} {#if trusted}<small>mph</small>{/if}</span>
  </div>
  <svg viewBox="0 0 640 390" role="img" aria-labelledby="park-title park-desc">
    <title id="park-title">Top-down wind diagram for {game.venue}</title>
    <desc id="park-desc">{geometry ? trusted ? 'Park wall geometry with the verified carry and cross wind.' : 'Park wall geometry; wind vectors are withheld because source provenance is incomplete.' : 'Park geometry is not present; no generic wall shape is substituted.'}</desc>
    <defs>
      <pattern id={`park-hatch-${game.game_pk}`} width="10" height="10" patternUnits="userSpaceOnUse" patternTransform="rotate(45)">
        <line x1="0" y1="0" x2="0" y2="10" class="hatch-line" />
      </pattern>
      <marker id={`wind-arrow-${game.game_pk}`} viewBox="0 0 10 10" refX="9" refY="5" markerWidth="6" markerHeight="6" orient="auto-start-reverse">
        <path d="M 0 0 L 10 5 L 0 10 Z" class="wind-marker" />
      </marker>
    </defs>
    <g class="field-grid">
      {#each [80, 160, 240, 320, 400, 480, 560] as x}<line x1={x} y1="42" x2={x} y2="344" />{/each}
      {#each [70, 130, 190, 250, 310] as y}<line x1="42" y1={y} x2="598" y2={y} />{/each}
    </g>
    {#if geometry}
      {#each RANGE_FEET as feet}
        <path d={rangeArc(feet)} class="range-arc" />
        <text class="range-label" x="306" y={HOME_Y - feet * PX_PER_FT - 4} text-anchor="end">{feet} ft</text>
      {/each}
    {/if}
    <path d="M 320 344 L 294 318 L 320 292 L 346 318 Z" class="diamond" />
    <path d="M 320 344 Q 320 205 320 95" class="centerline" />
    {#if geometry}
      {#if wallSegments.length}
        <line x1={wall[0].x} y1={wall[0].y} x2={wall[1].x} y2={wall[1].y} class="foul-line" />
        {#each wallSegments as segment}
          <line
            x1={segment.from.x}
            y1={segment.from.y}
            x2={segment.to.x}
            y2={segment.to.y}
            class="wall-seg"
            class:tall-wall-seg={segment.height >= 30}
            style={`stroke-width:${2 + Math.min(3.5, segment.height / 9)}`}
          />
        {/each}
        <line x1={wall[wall.length - 1].x} y1={wall[wall.length - 1].y} x2={wall[0].x} y2={wall[0].y} class="foul-line" />
      {:else}
        <path d={toPath(wall)} class="park-wall" />
      {/if}
      {#each distanceStamps as stamp}
        <text class="wall-distance" x={stamp.x} y={stamp.y} text-anchor="middle">{stamp.text}</text>
      {/each}
    {:else}
      <path d="M 135 268 Q 106 160 188 85 Q 320 20 452 85 Q 534 160 505 268" class="park-wall missing-wall" />
      <path d="M 112 52 H 528 V 282 H 112 Z" fill={`url(#park-hatch-${game.game_pk})`} class="geometry-mask" />
      <g class="missing-geometry">
        <rect x="180" y="151" width="280" height="64" />
        <text x="320" y="177">PARK GEOMETRY NOT PRESENT</text>
        <text x="320" y="198">outline withheld · no generic substitute</text>
      </g>
    {/if}
    {#if Boolean(game.dome_active)}
      <g class="becalmed"><path d="M 267 126 Q 320 82 373 126" /><text x="320" y="151">ROOF ACTIVE · BECALMED</text></g>
    {:else if wind != null}
      <g
        class="wind-streams"
        class:is-calm={windPeriod == null}
        transform={`rotate(${direction} 320 192)`}
        style={windPeriod == null ? '' : `--period:${windPeriod}s`}
      >
        {#each [-54, -18, 18, 54] as offset}
          <path d={`M ${170 + offset} 276 C ${235 + offset} 235, ${398 + offset} 151, ${474 + offset} 103`} marker-end={`url(#wind-arrow-${game.game_pk})`} />
        {/each}
      </g>
      <g class="compass" transform="translate(554 70)"><circle r="27" /><path d="M 0 20 V -20 M -5 -10 L 0 -20 L 5 -10" /><text y="-31">N</text></g>
      <g class="wind-decomp" transform="translate(554 150)">
        <line x1="0" y1="0" x2="0" y2={-carryVector} marker-end={`url(#wind-arrow-${game.game_pk})`} />
        <text class="decomp-label" x="6" y={-carryVector - 6}>C {signed(wind, 1)}</text>
        {#if cross != null}
          <line x1="0" y1="0" x2={crossVector} y2="0" marker-end={`url(#wind-arrow-${game.game_pk})`} />
          <line x1="0" y1="0" x2={crossVector} y2={-carryVector} class="decomp-resultant" />
          <text
            class="decomp-label"
            x={crossVector + (crossVector < 0 ? -4 : 4)}
            y="12"
            text-anchor={crossVector < 0 ? 'end' : 'start'}
          >X {signed(cross, 1)}</text>
        {/if}
      </g>
    {/if}
  </svg>
  <figcaption>
    {#if trusted}<span>CROSS {signed(cross, 1)} mph</span>
    <span>AIR {game.air_density_index == null ? '—' : game.air_density_index.toFixed(1)}</span>{:else}<span class="receipt-alert">SOURCE UNVERIFIED · WEATHER VECTORS HIDDEN</span>{/if}
    <span>{geometry ? `GEOMETRY · ${geometry.source}` : 'geometry gate closed'}</span>
    {#if geometry && wallHeightMin != null && wallHeightMax != null}
      <span>WALL {wallHeightMin}–{wallHeightMax} FT · THICKER STROKE = TALLER WALL</span>
    {/if}
  </figcaption>
</figure>
