<script lang="ts">
  import { onMount, tick } from 'svelte';
  import ThemeToggle from './components/ThemeToggle.svelte';
  import { ageHours } from './lib/format';
  import { now, startSlateRefresh } from './lib/clock';
  import { loadSlate } from './lib/data';
  import { fixtureLoadedMarket, loadMarket, type LoadedMarket } from './lib/market';
  import { parseRoute, routeTitle, type Route } from './lib/router';
  import { track } from './lib/telemetry';
  import type { LoadedSlate } from './lib/types';
  import Batters from './views/Batters.svelte';
  import Digest from './views/Digest.svelte';
  import GameDetail from './views/GameDetail.svelte';
  import Method from './views/Method.svelte';
  import NotFound from './views/NotFound.svelte';
  import Share from './views/Share.svelte';
  import Slate from './views/Slate.svelte';
  import Trust from './views/Trust.svelte';

  interface AppViewTransition {
    finished: Promise<void>;
    skipTransition: () => void;
  }

  let route: Route = { name: 'slate' };
  let lastRoute: Route = { name: 'slate' };
  let loaded: LoadedSlate | null = null;
  let market: LoadedMarket | null = null;
  let online = true;
  let firstRoute = true;
  let slateScrollY = 0;
  let lastSlateGamePk: number | null = null;
  let lastSlateControl: 'game' | 'share' | null = null;
  let scrolled = false;
  let refreshing = false;
  let sentinel: HTMLDivElement;
  let activeViewTransition: AppViewTransition | null = null;

  function ribbonSummary(value: LoadedSlate): string {
    const checked = `${value.payload.games.length} games checked`;
    const conflicts = value.duplicateConflicts ?? value.payload.games.filter((game) => game.data_conflict).length;
    const exact = Math.max(0, (value.duplicatesCollapsed ?? 0) - conflicts);
    const notes = [
      conflicts ? `${conflicts} data ${conflicts === 1 ? 'conflict' : 'conflicts'} flagged` : '',
      exact ? `${exact} exact ${exact === 1 ? 'duplicate' : 'duplicates'} collapsed` : '',
    ].filter(Boolean);
    if (value.source === 'network') return [checked, ...notes].join(' · ');
    if (value.source === 'cache') return `${checked} · last verified copy`;
    return `${checked} · sample data, not live`;
  }

  async function refreshFeed() {
    if (refreshing) return;
    refreshing = true;
    const next = await loadSlate();
    loaded = next;
    market = await loadMarket();
    refreshing = false;
  }

  function syncRoute() {
    const hash = location.hash;
    if (hash && !hash.startsWith('#/')) {
      const element = document.getElementById(hash.slice(1));
      if (element) {
        element.scrollIntoView({ block: 'start' });
        element.focus({ preventScroll: true });
      }
      return;
    }

    const next = parseRoute(hash);
    if (lastRoute.name === 'slate') {
      slateScrollY = window.scrollY;
      lastSlateGamePk = next.name === 'game' || next.name === 'share' ? next.gamePk : null;
      lastSlateControl = next.name === 'game' || next.name === 'share' ? next.name : null;
    }
    const returning = next.name === 'slate' && (lastRoute.name === 'game' || lastRoute.name === 'share');
    const initial = firstRoute;
    const reduce = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    const transitionDocument = document as Document & {
      startViewTransition?: (callback: () => void | Promise<void>) => AppViewTransition;
    };
    const swap = async () => {
      route = next;
      lastRoute = next;
      await tick();
      window.scrollTo({ top: returning ? slateScrollY : 0, behavior: 'instant' });
      if (!initial) {
        const cardLink = returning && lastSlateGamePk != null
          ? document.querySelector<HTMLAnchorElement>(`.game-card__link[href="#/game/${lastSlateGamePk}"]`)
          : null;
        const origin = lastSlateControl === 'share'
          ? cardLink?.closest('.game-card')?.querySelector<HTMLButtonElement>('.icon-button')
          : cardLink;
        (origin ?? document.getElementById('main-content'))?.focus({ preventScroll: true });
      }
    };

    firstRoute = false;
    if (!initial && !reduce && transitionDocument.startViewTransition) {
      try { activeViewTransition?.skipTransition(); } catch { /* already finished */ }
      const transition = transitionDocument.startViewTransition(swap);
      activeViewTransition = transition;
      void transition.finished.catch(() => { /* superseded route transitions are expected */ }).finally(() => {
        if (activeViewTransition === transition) activeViewTransition = null;
      });
    } else {
      void swap();
    }
    track('page_view', { view: next.name });
  }

  onMount(() => {
    if ('scrollRestoration' in history) history.scrollRestoration = 'manual';
    online = navigator.onLine;
    void refreshFeed();
    syncRoute();
    const onOnline = () => online = true;
    const onOffline = () => online = false;
    // Honour the 15-min cadence /#/method promises; without this the slate froze at mount.
    // Odds ride the same refresh (a tiny 2×/day artifact; over-polling it is harmless).
    const stopRefresh = startSlateRefresh((value) => { loaded = value; loadMarket().then((v) => market = v); });
    const observer = new IntersectionObserver(([entry]) => scrolled = !entry.isIntersecting);
    observer.observe(sentinel);
    window.addEventListener('hashchange', syncRoute);
    window.addEventListener('online', onOnline);
    window.addEventListener('offline', onOffline);
    return () => {
      stopRefresh();
      observer.disconnect();
      window.removeEventListener('hashchange', syncRoute);
      window.removeEventListener('online', onOnline);
      window.removeEventListener('offline', onOffline);
    };
  });

  // Reactive on the ticking clock, so age is a live reading and `stale` can actually fire.
  $: age = loaded ? ageHours(loaded.payload.generated_at, $now) : 0;
  $: staleAfterMinutes = loaded?.payload.freshness?.stale_after_minutes ?? 45;
  $: stale = age * 60 > staleAfterMinutes;
  // Pair the fixture slate with the sample market; never join live odds onto fixture game_pks (or
  // vice versa). Live/cache slates use the network market (or null → cards show no market row).
  $: marketForUi = loaded?.source === 'fixture' ? fixtureLoadedMarket : market;
  $: example = loaded?.payload.games.find((game) => game.daily_pf_runs != null);
  $: selectedGame = (() => {
    if (route.name !== 'game') return undefined;
    const gamePk = route.gamePk;
    return loaded?.payload.games.find((game) => game.game_pk === gamePk);
  })();
  $: selectedShareGame = (() => {
    if (route.name !== 'share') return undefined;
    const gamePk = route.gamePk;
    return loaded?.payload.games.find((game) => game.game_pk === gamePk);
  })();
  // Permalink polish: title reflects the actual game once resolved.
  $: {
    const g = route.name === 'game' ? selectedGame : route.name === 'share' ? selectedShareGame : undefined;
    const label = g
      ? `${g.away_team} at ${g.home_team}${route.name === 'share' ? ' · Share' : ''}`
      : routeTitle(route);
    document.title = `${label} · Prestige Atmospheric`;
  }

  const active = (name: Route['name']) => route.name === name || (name === 'slate' && route.name === 'game');
  const feedbackHref = (answer: string) => `mailto:${import.meta.env.VITE_FEEDBACK_EMAIL ?? ''}?subject=${encodeURIComponent('Prestige Atmospheric feedback')}&body=${encodeURIComponent(`Did the instrument explain today's movement? ${answer}\n\nOne thing I still need:\n`)}`;
</script>

<a class="skip-link" href="#main-content">Skip to main content</a>
<div class="site-frame">
  <div class="scroll-sentinel" bind:this={sentinel} aria-hidden="true"></div>
  <header class="site-header" class:is-scrolled={scrolled}>
    <a class="brand" href="#/" aria-label="Prestige Atmospheric home">
      <span class="brand-mark" aria-hidden="true"><i></i><i></i><i></i></span>
      <span><strong>PRESTIGE</strong><small>ATMOSPHERIC</small></span>
    </a>
    <nav aria-label="Primary navigation">
      <a class:active={active('slate')} href="#/">Slate</a>
      <a class:active={active('batters')} href="#/batters">Lineups</a>
      <a class:active={active('trust')} href="#/trust">Data Health</a>
      <a class:active={active('method')} href="#/method">Method</a>
    </nav>
    <ThemeToggle />
  </header>

  {#if loaded}
    <aside class="data-ribbon source-{loaded.source}" class:is-stale={stale} class:is-mismatch={Boolean(loaded.schemaMismatch) || loaded.payload.games.some((game) => game.data_conflict)} aria-live="polite">
      <span class="ribbon-pulse" aria-hidden="true"></span>
      <strong>{loaded.source === 'network' ? 'LIVE PAYLOAD' : loaded.source === 'cache' ? 'DEVICE COPY' : 'OFFLINE FIXTURE'}</strong>
      <span title={loaded.note}>{ribbonSummary(loaded)}</span>
      {#if loaded.cause}<span class="cause-chip" title={loaded.detail}>{loaded.cause}</span>{/if}
      <span class="ribbon-meta" title={loaded.payload.generated_at}>{loaded.payload.model_version} · {age < 1 ? `${Math.round(age * 60)}m` : `${Math.round(age)}h`} old</span>
      {#if loaded.schemaMismatch}<span class="mismatch-chip">DATA FORMAT CHANGED · got {loaded.schemaMismatch.received} · app supports {loaded.schemaMismatch.expected}</span>{/if}
      {#if loaded.duplicateConflicts || loaded.payload.games.some((game) => game.data_conflict)}<span class="mismatch-chip">FEED CONFLICT · FACTORS WITHHELD</span>{/if}
      {#if !online}<span class="offline-chip">OFFLINE</span>{/if}
      {#if stale}<span class="stale-chip">STALE · VERIFY BEFORE USE</span>{/if}
      {#if loaded.source !== 'network' || stale || loaded.schemaMismatch}<button class="ribbon-retry" type="button" onclick={refreshFeed} disabled={refreshing}>{refreshing ? 'Refreshing…' : 'Retry live feed'}</button>{/if}
    </aside>
  {/if}

  <main id="main-content" tabindex="-1">
    {#if !loaded}
      <section class="loading-shell" aria-live="polite" aria-label="Reading station data">
        <div class="loading-rule"></div>
        <p>Reading station data…</p>
        <div class="skeleton-title" aria-hidden="true"></div>
        <div class="skeleton-lede" aria-hidden="true"></div>
        <div class="skeleton-strip" aria-hidden="true"><i></i><i></i><i></i><i></i><i></i></div>
        <div class="game-grid" aria-hidden="true">
          <div class="skeleton-card"></div>
          <div class="skeleton-card"></div>
          <div class="skeleton-card"></div>
        </div>
      </section>
    {:else if route.name === 'slate'}
      <Slate payload={loaded.payload} source={loaded.source} {stale} market={marketForUi} />
    {:else if route.name === 'game'}
      <GameDetail game={selectedGame} fixture={loaded.source === 'fixture'} market={marketForUi} slateDate={loaded.payload.date} generatedAt={loaded.payload.generated_at} source={loaded.source} {stale} />
    {:else if route.name === 'share'}
      <Share game={selectedShareGame} date={loaded.payload.date} source={loaded.source} {stale} modelVersion={loaded.payload.model_version} />
    {:else if route.name === 'digest'}
      <Digest payload={loaded.payload} source={loaded.source} {stale} />
    {:else if route.name === 'batters'}
      <Batters slate={loaded.payload} source={loaded.source} {stale} />
    {:else if route.name === 'trust'}
      <Trust slate={loaded.payload} source={loaded.source} {stale} />
    {:else if route.name === 'method'}
      <Method {example} />
    {:else}
      <NotFound path={route.path} />
    {/if}
  </main>

  <footer class="site-footer">
    <div class="footer-station"><span class="brand-mark mini" aria-hidden="true"><i></i><i></i><i></i></span><div><strong>PRESTIGE ATMOSPHERIC</strong><small>Weather physics, with its uncertainty left on.</small></div></div>
    <div class="feedback-question"><span>Did this explain today’s movement?</span><a href={feedbackHref('Yes')} onclick={() => track('feedback', { answer: 'yes' })}>Yes</a><a href={feedbackHref('Needs more context')} onclick={() => track('feedback', { answer: 'context' })}>Needs context</a></div>
    <p class="legal">Information only—not wagering advice. If market references are legal where you live, you must be 21+ or the legal age in your jurisdiction. Set limits and never chase losses.</p>
    <div class="footer-links"><a href="#/digest">Share today’s slate</a><a href="#/method">Honesty doctrine</a><span>{loaded?.payload.model_version ?? 'MODEL NOT LOADED'}</span></div>
  </footer>
</div>
